module encoder_64b66b (
    input  logic         clk_in,              // Clock signal
    input  logic         rst_in,              // Asynchronous reset (active high)
    input  logic [63:0]  encoder_data_in,     // 64-bit data input
    input  logic [7:0]   encoder_control_in,  // 8-bit control input
    output logic [65:0]  encoder_data_out     // 66-bit encoded output
);

    logic [1:0]  sync_word;
    logic [63:0] encoded_data;

    // Simplified get_output function
    always_comb begin
        case (encoder_control_in)
            8'b00000000: encoder_data_out = {sync_word, encoded_data};
            8'b11111111: encoder_data_out = {8'h1E, encoded_data};
            8'b00011111: encoder_data_out = {encoded_data[39:40], 4'h0, 7'h00, 7'h00, 7'h00, 7'h00, 7'h00};
            8'b00000001: encoder_data_out = {encoded_data[63:8], encoder_data_in[7:0]};
            8'b11111110: encoder_data_out = {7'h00, 7'h00, 7'h00, 7'h00, 7'h00, 7'h00, 6'b000000, encoded_data[7:0]};
            8'b11111100: encoder_data_out = {7'h00, 7'h00, 7'h00, 7'h00, 7'h00, 5'b00000, encoded_data[15:0]};
            8'b11111000: encoder_data_out = {7'h00, 7'h00, 7'h00, 3'b000, encoded_data[31:0]};
            8'b11110000: encoder_data_out = {7'h00, 7'h00, 2'b00, encoded_data[39:32], 0};
            8'b11100000: encoder_data_out = {7'h00, 1'b0, encoded_data[47:0]};
            8'b11000000: encoder_data_out = encoded_data[55:0];
            default: encoder_data_out = {sync_word, encoded_data};
        endcase
    end

    // Simplified synchronization logic
    always_ff @(posedge clk_in or posedge rst_in) begin
        if (rst_in) begin
            sync_word <= 2'b00;
            encoded_data <= 64'b0;
        end else begin
            sync_word <= encoder_control_in;
            encoded_data <= (encoder_control_in == 8'b00000001) ? encoded_data[63:8] : 64'b0;
        end
    end

    // Synchronized encoded_ctrl_words with simplified case structure
    always @(posedge clk_in or posedge rst_in) begin
        if (rst_in) begin
            encoded_ctrl_words <= 56'b0;
        end else begin
            case (encoder_control_in)
                8'b11111111: begin
                    encoded_ctrl_words <= {7'h00, 7'h00, 7'h00, 7'h00, 7'h00, 7'h00, 7'h00, 7'h00};
                8'b00011111: begin
                    encoded_ctrl_words <= {encoded_data[39:40], 4'h0, 7'h00, 7'h00, 7'h00, 7'h00, 7'h00};
                8'b00000001: begin
                    encoded_ctrl_words <= encoded_data[63:8];
                end
                8'b11111110: begin
                    encoded_ctrl_words <= {7'h00, 7'h00, 7'h00, 7'h00, 7'h00, 7'h00, encoded_data[7:0]};
                8'b11111100: begin
                    encoded_ctrl_words <= {7'h00, 7'h00, 7'h00, 7'h00, 7'h00, 5'b00000, encoded_data[15:0]};
                8'b11111000: begin
                    encoded_ctrl_words <= {7'h00, 7'h00, 7'h00, 3'b000, encoded_data[31:0]};
                8'b11100000: begin
                    encoded_ctrl_words <= {7'h00, 7'h00, 2'b00, encoded_data[39:0]};
                8'b11000000: begin
                    encoded_ctrl_words <= 56'h0;
                end
                default: encoded_ctrl_words <= 56'b0;
            endcase
        end
    end

    // Synchronize sync_ctrl_word and type_field
    always @(posedge clk_in or posedge rst_in) begin
        if (rst_in) begin
            sync_ctrl_word <= 2'b00;
            type_field <= 8'b0;
        end else begin
            sync_ctrl_word <= encoder_control_in;
            type_field <= (encoder_control_in != 8'b00000000) ? get_output(encoder_data_in, encoder_control_in) : 8'b0;
        end
    end

endmodule

output.rtl/priority_encoder.v:
module priority_encoder_8x3 (
    input [7:0] in,
    output reg [2:0] out
);

    // Initialize output to 0
    always @ (in) begin
        out = 3'b000;
    end

    // Check priority order from bit 7 to bit 0
    always @ (in) begin
        if (in[7]) begin
            out = 3'b111;
        end else if (in[6]) begin
            out = 3'b110;
        end else if (in[5]) begin
            out = 3'b101;
        end else if (in[4]) begin
            out = 3'b011;
        end else if (in[3]) begin
            out = 3'b010;
        end else if (in[2]) begin
            out = 3'b001;
        end else if (in[1]) begin
            out = 3'b000;
        end
    end

endmodule

input.rtl/priority_encoder.v:
module priority_encoder_8x3 (
    input       [7:0] in      ,   // 8 input lines
    output reg  [2:0] out         // 3 output lines
);

always @(*) begin
    if (in[7])
        out = 3'b111;
    else if (in[6])
        out = 3'b110;
    else if (in[5])
        out = 3'b101;
    else if (in[4])
        out = 3'b100;
    else if (in[3])
        out = 3'b011;
    else if (in[2])
        out = 3'b010;
    else if (in[1])
        out = 3'b001;
    else if (in[0])
        out = 3'b000;
    else
        out = 3'b000; // Default case when no inputs are active
end

endmodule

output.rtl/cascaded_encoder.v:
module cascaded_encoder #(parameter N = 8) (
    input [N-1:0] input_signal,
    output reg [M-1:0] out,
    output reg [M-1:0] out_upper_half,
    output reg [M-1:0] out_lower_half
);
    // Calculate output width M based on parameter N
    localparam M = N > 1 ? log2ceil(N) : 1;

    // Instantiate two priority encoders for upper and lower halves
    priority_encoder #(N, M) encoder_upper(.input_signal(input_signal[N/2-1:0]), .out(out_upper_half));
    priority_encoder #(N, M) encoder_lower(.input_signal(input_signal[N/2:0]), .out(out_lower_half));

    // Determine which half has the highest priority active bit
    always @(encoder_upper.out or encoder_lower.out) begin
        if (encoder_upper.out != 0) begin
            out = encoder_upper.out;
            out_upper_half = out;
            out_lower_half = 0;
        end else if (encoder_lower.out != 0) begin
            out = encoder_lower.out;
            out_upper_half = 0;
            out_lower_half = encoder_lower.out;
        end else begin
            out = 0;
            out_upper_half = 0;
            out_lower_half = 0;
        end
    end

endmodule

output.rtl/Attenuator.sv:
module Attenuator (
    input        clk,
    input        reset,
    input  [4:0] data,
    output reg   ATTN_CLK,
    output reg   ATTN_DATA,
    output reg   ATTN_LE
);

// Internal Signals
reg        clk_div2;
reg  [1:0] current_state, next_state;
reg  [4:0] shift_reg;
reg  [2:0] bit_count;
reg  [4:0] old_data;

// Parameters for FSM States
localparam IDLE  = 2'b00,
           LOAD  = 2'b01,
           SHIFT = 2'b10,
           LATCH = 2'b11;

// Clock divider
always @(posedge clk) begin
    clk_div2 <= ~clk_div2;
end

// FSM
always @(posedge clk or posedge reset) begin
    if (reset) begin
        current_state <= IDLE;
        ATTN_CLK      <= 1'b0;
        ATTN_DATA     <= 1'b0;
        ATTN_LE       <= 1'b0;
        shift_reg     <= 5'b00000;
        bit_count     <= 3'd0;
        old_data      <= 5'b00000;
    end else begin
        case (current_state)
            IDLE: begin
                if (data != old_data) begin
                    current_state <= LOAD;
                    ATTN_CLK      <= 1'b0;
                    shift_reg     <= data;
                    bit_count     <= 3'd0;
                end
            end
            LOAD: begin
                bit_count <= bit_count + 1'b1;
                if (bit_count == 5'd5) begin
                    current_state <= SHIFT;
                    ATTN_CLK      <= ~ATTN_CLK;
                    ATTN_DATA     <= shift_reg[bit_count - 1];
                    bit_count     <= 3'd0;
                end
            end
            SHIFT: begin
                bit_count <= bit_count + 1'b1;
                if (bit_count == 5'd5) begin
                    current_state <= LATCH;
                    ATTN_CLK      <= 1'b0;
                    ATTN_LE       <= 1'b1;
                    bit_count     <= 3'd0;
                end
            end
            LATCH: begin
                bit_count <= 3'd0;
                ATTN_CLK      <= 1'b0;
                ATTN_LE       <= 1'b0;
            end
        endcase
    end
end

endmodule

