module fir_filter (
    input logic clk,                 // Clock signal
    input logic reset,               // Reset signal
    input logic signed [15:0] input_sample,  // Input data sample
    output logic signed [15:0] output_sample, // Output filtered sample
    input logic signed [15:0] coeff0, // Coefficient for current input sample
    input logic signed [15:0] coeff1, // Coefficient for first delay
    input logic signed [15:0] coeff2, // Coefficient for second delay
    input logic signed [15:0] coeff3  // Coefficient for third delay
);

    // Declare internal storage for delay elements and accumulation
    logic signed [15:0] sample_delay1, sample_delay2, sample_delay3;
    logic signed [31:0] accumulator;

    // Sequential block to handle operations on clock or reset
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            // Reset state: Clear all registers and output
            sample_delay1 <= 'b0;
            sample_delay2 <= 'b0;
            sample_delay3 <= 'b0;
            accumulator <= 0;
            output_sample <= 'b0;
        end else begin
            // Regular operation: Shift samples, compute filtered output
            sample_delay1 <= input_sample;
            sample_delay2 <= sample_delay1;
            sample_delay3 <= sample_delay2;

            // Perform FIR filtering logic
            accumulator <= (accumulator << 1) | (coeff0 * sample_delay1) |
                           (coeff1 * sample_delay2) | (coeff2 * sample_delay3) |
                           (coeff3 * input_sample);

            // Ensure output is 4 cycles delayed
            if (clk_counter == 4) begin
                output_sample <= accumulator >> 1; // Divide by 2 for signed 16-bit result
                clk_counter <= 0; // Reset counter
            end else begin
                clk_counter <= clk_counter + 1;
            end
        end
    end

endmodule

module fir_filter (
    input wire clk,                  // Clock signal
    input wire reset,                // Asynchronous reset
    input wire [15:0] data_in,       // Input data
    output reg [15:0] data_out,      // Filtered output data
    input wire [1:0] window_type     // Window type selector: 0-Rectangular, 1-Hanning, 2-Hamming, 3-Blackman
);

    reg [15:0] coeff0, coeff1, coeff2, coeff3, coeff4, coeff5, coeff6, coeff7;
    reg [15:0] shift_reg0, shift_reg1, shift_reg2, shift_reg3, shift_reg4, shift_reg5, shift_reg6, shift_reg7;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            // Reset logic to zero data_out and shift registers
            data_out <= 16'b0;
            shift_reg0 <= 16'b0;
            shift_reg1 <= 16'b0;
            shift_reg2 <= 16'b0;
            shift_reg3 <= 16'b0;
            shift_reg4 <= 16'b0;
            shift_reg5 <= 16'b0;
            shift_reg6 <= 16'b0;
            shift_reg7 <= 16'b0;
        end else begin
            case (window_type)
                2'b00: begin // Rectangular Window
                    coeff0 = 16'h0A;
                    coeff1 = 16'h0B;
                    coeff2 = 16'h0C;
                    coeff3 = 16'h0D;
                    coeff4 = 16'h0E;
                    coeff5 = 16'h0F;
                    coeff6 = 16'h10;
                    coeff7 = 16'h11;
                end
                2'b01: begin // Hanning Window
                    coeff0 = 16'h02;
                    coeff1 = 16'h04;
                    coeff2 = 16'h08;
                    coeff3 = 16'h12;
                    coeff4 = 16'h12;
                    coeff5 = 16'h08;
                    coeff6 = 16'h04;
                    coeff7 = 16'h02;
                end
                2'b10: begin // Hamming Window
                    coeff0 = 16'h03;
                    coeff1 = 16'h06;
                    coeff2 = 16'h09;
                    coeff3 = 16'h11;
                    coeff4 = 16'h11;
                    coeff5 = 16'h09;
                    coeff6 = 16'h06;
                    coeff7 = 16'h03;
                end
                2'b11: begin // Blackman Window
                    coeff0 = 16'h01;
                    coeff1 = 16'h02;
                    coeff2 = 16'h05;
                    coeff3 = 16'h09;
                    coeff4 = 16'h09;
                    coeff5 = 16'h05;
                    coeff6 = 16'h02;
                    coeff7 = 16'h01;
                end
            endcase

            // Shift register updates
            shift_reg0 <= shift_reg1;
            shift_reg1 <= shift_reg2;
            shift_reg2 <= shift_reg3;
            shift_reg3 <= shift_reg4;
            shift_reg4 <= shift_reg5;
            shift_reg5 <= shift_reg6;
            shift_reg6 <= shift_reg7;
            shift_reg7 <= data_in;

            // Output calculation
            data_out <= ((coeff0 * shift_reg0) +
                         (coeff1 * shift_reg1) +
                         (coeff2 * shift_reg2) +
                         (coeff3 * shift_reg3) +
                         (coeff4 * shift_reg4) +
                         (coeff5 * shift_reg5) +
                         (coeff6 * shift_reg6) +
                         (coeff7 * shift_reg7)) >>> 4;
        end
    end
endmodule

