module glitch_free_mux(
    input clk1,
    input clk2,
    input sel,
    input rst_n,
    output reg clkout
);

    reg [1:0] state;
    reg [1:0] next_state;
    reg [1:0] sel_state;

    // State transition logic
    always @(posedge clk1 or posedge clk2 or posedge rst_n) begin
        if (rst_n) begin
            state <= 0;
            clkout <= 0;
        end else begin
            state <= next_state;
            clkout <= sel_state;
        end
    end

    // State encoding
    always @(*) begin
        case (state)
            0: begin
                next_state <= sel ? 1 : 0;
                sel_state <= sel;
            end
            1: begin
                next_state <= sel ? 2 : 3;
                sel_state <= sel;
            end
            2: begin
                next_state <= 0;
                sel_state <= sel;
            end
            3: begin
                next_state <= sel ? 0 : 1;
                sel_state <= sel;
            end
        endcase
    end

    // Clock enable logic
    always @(sel or next_state) begin
        case (next_state)
            1: begin
                clkout <= sel;
            end
            2: begin
                clkout <= ~sel;
            end
        endcase
    end

endmodule

input.rtl/glitch_free_mux.sv:
module glitch_free_mux
(
    input clk1,		//input clk1
    input clk2,		// input clk2
    input rst_n,	// async reset
    input sel,		// selection line
    output  clkout	// clock output
);

reg clkout_reg ;
reg clk1_enable, clk2_enable;
reg clk1_out, clk2_out ;


// CLK1 ENABLE LOGIC
always@(posedge clk1 or negedge rst_n  ) begin
        if (~rst_n) begin
            clk1_enable <= 0 ; 
        end else begin
            clk1_enable <= ~ clk2_enable & ~sel  ;
        end 
end

// CLK2 ENABLE LOGIC
always@(posedge clk2 or negedge rst_n  ) begin
       if (~rst_n) begin
           clk2_enable <= 0 ; 
       end else begin
           clk2_enable <= ~ clk1_enable & sel  ;
       end 
end

// OUTPUT LOGIC
assign clkout = (clk1 & clk1_enable) | (clk2 & clk2_enable) ;

endmodule

output.rtl/glitch_free_mux.sv:
module glitch_free_mux
(
    input clk1,		//input clk1
    input clk2,		// input clk2
    input rst_n,	// async reset
    input sel,		// selection line
    output  clkout	// clock output
);

reg clkout_reg ;
reg clk1_enable, clk2_enable;
reg clk1_out, clk2_out ;

// Two-flop clock synchronizer for clk1
always @(posedge clk1 or negedge rst_n) begin
    if (!rst_n) begin
        clk1_enable <= 0;
        clk1_out <= 0;
    end else begin
        clk1_enable <= ~clk2_enable & sel;
        clk1_out <= clk1_enable & clk1;
    end
end

// Two-flop clock synchronizer for clk2
always @(posedge clk2 or negedge rst_n) begin
    if (!rst_n) begin
        clk2_enable <= 0;
        clk2_out <= 0;
    end else begin
        clk2_enable <= ~clk1_enable & sel;
        clk2_out <= clk2_enable & clk2;
    end
end

// OUTPUT LOGIC
assign clkout = (clk1_out & clk1_enable) | (clk2_out & clk2_enable);

endmodule

