module cache_mshr #(
    parameter INSTANCE_ID                   = "mo_mshr"             ,
    parameter MSHR_SIZE                     = 32                    ,
    parameter CS_LINE_ADDR_WIDTH            = 10                    ,
    parameter WORD_SEL_WIDTH                = 4                     ,
    parameter WORD_SIZE                     = 4                     ,
    parameter MSHR_ADDR_WIDTH               = $clog2(MSHR_SIZE)     ,
    parameter TAG_WIDTH                     = 32 - (CS_LINE_ADDR_WIDTH+ $clog2(WORD_SIZE) + WORD_SEL_WIDTH),
    parameter CS_WORD_WIDTH                 = WORD_SIZE * 8 ,
    parameter DATA_WIDTH                    = WORD_SEL_WIDTH + WORD_SIZE + CS_WORD_WIDTH + TAG_WIDTH
) (
    input wire clk,
    input wire reset,

    // allocate
    input wire                          allocate_valid,
    output wire                         allocate_ready,
    input wire [CS_LINE_ADDR_WIDTH-1:0] allocate_addr,
    input wire                          allocate_rw,
    input wire [DATA_WIDTH-1:0]         allocate_data,
    output wire [MSHR_ADDR_WIDTH-1:0]   allocate_id,
    output wire                         allocate_pending,
    output wire [MSHR_ADDR_WIDTH-1:0]   allocate_previd,

    // finalize
    input wire                          finalize_valid,
    input wire [MSHR_ADDR_WIDTH-1:0]    finalize_id
);

    reg [DATA_WIDTH-1:0] entry_valid_table_q [MSHR_SIZE-1:0];
    reg [MSHR_ADDR_WIDTH-1:0] next_idx_table [MSHR_SIZE-1:0];
    reg [WORD_SEL_WIDTH-1:0] write_data [MSHR_SIZE-1:0];
    reg [WORD_SEL_WIDTH-1:0] byte_enable_signal [MSHR_SIZE-1:0];
    reg [CS_LINE_ADDR_WIDTH-1:0] cache_line_addr [MSHR_SIZE-1:0];

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            for (int i = 0; i < MSHR_SIZE; i = i + 1) begin
                entry_valid_table_q[i] <= 0;
                next_idx_table[i] <= 0;
                write_data[i] <= 0;
                byte_enable_signal[i] <= 0;
                cache_line_addr[i] <= 0;
            end
        end else begin
            if (allocate_valid) begin
                cache_line_addr[next_idx_table[allocate_id]] = allocate_addr;
                write_data[next_idx_table[allocate_id]] = allocate_data;
                byte_enable_signal[next_idx_table[allocate_id]] = allocate_rw;
                entry_valid_table_q[next_idx_table[allocate_id]] <= 1;
                next_idx_table[allocate_id] <= next_idx;
            end
        end
    end

    always @(posedge clk) begin
        integer next_idx, next_idx_update;
        foreach (entry_valid_table_q[i]) begin
            if (entry_valid_table_q[i] && !allocate_pending) begin
                next_idx = next_idx_table[i];
                if (next_idx != 0) begin
                    next_idx_update = next_idx_table[next_idx];
                    if (next_idx_update == 0) begin
                        next_idx_table[i] = 0;
                        allocate_pending <= 1;
                    end else begin
                        next_idx_table[i] = next_idx_update;
                    end
                end
            end
        end
    end

    // Finalize logic
    always @(posedge clk or posedge reset) begin
        if (finalize_valid) begin
            integer finalize_idx;
            foreach (cache_line_addr[i]) begin
                if (entry_valid_table_q[i]) begin
                    finalize_idx = i;
                    entry_valid_table_q[i] <= 0;
                    cache_line_addr[i] <= finalize_id;
                end
            end
        end
    end

endmodule

module cache_mshr #(
    parameter INSTANCE_ID            = "mo_mshr"             ,
    parameter MSHR_SIZE                     = 32                    ,
    parameter CS_LINE_ADDR_WIDTH            = 10                    ,
    parameter WORD_SEL_WIDTH                = 4                     ,
    parameter WORD_SIZE                     = 4                     ,
    // Derived parameters
    parameter MSHR_ADDR_WIDTH               = $clog2(MSHR_SIZE)     , // default = 5
    parameter TAG_WIDTH                     = 32 - (CS_LINE_ADDR_WIDTH+ $clog2(WORD_SIZE) + WORD_SEL_WIDTH), // default = 16
    parameter CS_WORD_WIDTH                 = WORD_SIZE * 8 ,// default = 32 
    parameter DATA_WIDTH                    = WORD_SEL_WIDTH + WORD_SIZE + CS_WORD_WIDTH + TAG_WIDTH // default =  4 + 4 + 32 + 16 = 56
) (
    input wire clk,
    input wire reset,

     // memory fill
    input wire fill_valid,
    input wire [MSHR_ADDR_WIDTH-1:0]     fill_id,
    output reg [CS_LINE_ADDR_WIDTH-1:0] fill_addr,

    // dequeue
    output reg dequeue_valid,
    output reg [CS_LINE_ADDR_WIDTH-1:0] dequeue_addr,
    output reg dequeue_rw,
    output reg [DATA_WIDTH-1:0]         dequeue_data,
    output reg [MSHR_ADDR_WIDTH-1:0]    dequeue_id,
    input wire dequeue_ready,

    // allocate
    input wire allocate_valid,
    output reg allocate_ready,
    input wire [CS_LINE_ADDR_WIDTH-1:0] allocate_addr,
    input wire allocate_rw,
    input reg [DATA_WIDTH-1:0]         allocate_data,
    output reg [MSHR_ADDR_WIDTH-1:0]   allocate_id,
    output reg allocate_pending,
    output reg [MSHR_ADDR_WIDTH-1:0]   allocate_previd
);

    reg [CS_LINE_ADDR_WIDTH-1:0] cs_line_addr_table [0:MSHR_SIZE-1];
    reg [MSHR_SIZE-1:0] entry_valid_table_q, entry_valid_table_d;
    reg [MSHR_SIZE-1:0] is_write_table;

    reg [MSHR_SIZE-2:0] next_ptr_valid_table_q, next_ptr_valid_table_d;
    reg [MSHR_ADDR_WIDTH-1:0] next_index_ptr [0:MSHR_SIZE-1]; // ptr to the next index

    reg [MSHR_ADDR_WIDTH-1:0] allocate_id_q, allocate_id_d;

    reg [MSHR_ADDR_WIDTH-1:0] prev_idx;
    reg prev_idx_q;

    reg dequeue_valid_q, dequeue_valid_d ;
    reg [MSHR_ADDR_WIDTH-1:0] dequeue_id_q, dequeue_id_d ;


    reg [DATA_WIDTH-1:0] ram [0:MSHR_SIZE-1];
    reg [DATA_WIDTH-1:0] dequeue_data_int;

    always @(posedge clk) begin
        if (reset) begin
            entry_valid_table_q  <= '0;
            next_ptr_valid_table_q  <=  0;
            dequeue_valid_q <= 0;
            dequeue_valid_d <= 0;
            allocate_id_q       <=  0 ;
            prev_idx_q          <= 0 ;
        end else begin
            entry_valid_table_q  <= entry_valid_table_d;
            next_ptr_valid_table_q  <= next_ptr_valid_table_d;
            dequeue_valid_q <= dequeue_valid_d ;
            allocate_id_q       <= allocate_id_d       ;
            prev_idx_q          <= prev_idx ;
        end
    end

    always @(posedge clk) begin
        if (allocate_valid) begin
            if (allocate_rw == 1'b1) begin
                cs_line_addr_table[allocate_id_d]   <= allocate_addr;
                is_write_table[allocate_id_d]       <= 1'b1;
                entry_valid_table_d     <= 1'b1;
                next_ptr_valid_table_d  <= next_index_ptr[allocate_id_d];
                allocate_pending_d <= 1'b1;
            end else begin
                cs_line_addr_table[allocate_id_d]   <= allocate_addr;
                is_write_table[allocate_id_d]       <= 1'b0;
                entry_valid_table_d     <= 1'b0;
                next_ptr_valid_table_d  <= 0;
                allocate_pending_d <= 1'b0;
            end
        end
    end

    always @(posedge clk) begin
        if (dequeue_ready) begin
            dequeue_valid_q <= next_ptr_valid_table_q[allocate_id_q];
            dequeue_addr   <= cs_line_addr_table[allocate_id_q];
            dequeue_rw     <= is_write_table[allocate_id_q];
            dequeue_data   <= ram[allocate_id_q];
            dequeue_id_q   <= allocate_id_q;
            dequeue_valid_d <= 1'b1;
            prev_idx_q     <= next_index_ptr[allocate_id_q];
        end
    end

    always @(posedge clk) begin
        if (finalize_valid) begin
            entry_valid_table_d[finalize_id] = 0;
        end
    end

    assign allocate_pending_q = |next_ptr_valid_table_q[allocate_id_q];
    assign allocate_id = allocate_id_q;
    assign allocate_ready = ~next_ptr_valid_table_q[allocate_id_q];

    assign allocate_previd = prev_idx_q;

    always @(posedge clk) begin
        if (reset) begin
            prev_idx_q          <= 0 ;
        end else begin
            if (allocate_pending_d) begin
                next_index_ptr[prev_idx] <= allocate_id_q;
            end
        end
    end

    assign allocate_pending_d = |match_with_no_next;

    // SP RAM
    reg [DATA_WIDTH-1:0] ram [0:MSHR_SIZE-1];
    reg [DATA_WIDTH-1:0] dequeue_data_int;
    always @(posedge clk) begin
        if (allocate_fire) begin
            ram[allocate_id_d] <= allocate_data ;
        end
    end

    assign dequeue_valid_d = |addr_matches;

    assign dequeue_ready = dequeue_ready;

    // Miss Status Handling Registers (MSHR) entries allocation and finalize operations
    always @(posedge clk) begin
        if (fill_valid) begin
            cs_line_addr_table[fill_id] <= fill_addr;
            entry_valid_table_q <= 1'b1;
            next_ptr_valid_table_q <= next_index_ptr[fill_id];
        end
    end

    assign dequeue_id_d = fill_id;

    // Sequential update for dequeue operation
    always @(posedge clk) begin
        if (dequeue_valid_d) begin
            if (dequeue_id_d != dequeue_id_q) begin
                dequeue_id_q <= dequeue_id_d;
                dequeue_valid_q <= 1'b1;
            end else begin
                dequeue_id_q <= 0;
                dequeue_valid_q <= 0;
            end
        end
    end

    // Link the next entry for the same cache line
    always @(posedge clk) begin
        if (entry_valid_table_q[fill_id]) begin
            next_index_ptr[fill_id] <= next_ptr_valid_table_q[fill_id];
        end else {
            next_index_ptr[fill_id] <= 0;
        }
    end

endmodule

output.rtl/serial_line_code_converter.sv:
module serial_line_code_converter #(parameter CLK_DIV = 16)(
    input  logic clk,             // System clock
    input  logic reset_n,         // Active-low reset
    input  logic serial_in,       // Serial input signal
    input  logic [2:0] mode,      // Mode selector
    output logic serial_out       // Serial output signal
);

    // Internal signals
    logic [3:0] clk_counter;      // Clock divider counter
    logic clk_pulse;              // Clock pulse for sampling
    logic prev_serial_in;         // Previous serial input for edge detection
    logic prev_value;             // Holds the previous value of serial_in
    logic nrz_out;                // NRZ encoding output
    logic rz_out;                 // Return-to-Zero encoding output
    logic diff_out;               // Differential encoding output
    logic inv_nrz_out;            // Inverted NRZ output
    logic alt_invert_out;         // NRZ with alternating bit inversion output
    logic alt_invert_state;       // State for alternating inversion
    logic parity_out;             // Parity Bit Output
    logic scrambled_out;          // Scrambled NRZ output
    logic edge_triggered_out;     // Edge-Triggered NRZ output

    // Clock Pulse Generation
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            clk_counter <= 0;
        end else begin
            if (clk_counter == CLK_DIV - 1) begin
                clk_pulse <= ~clk_pulse;
                clk_counter <= 0;
            end else begin
                clk_counter <= clk_counter + 1;
            end
        end
    end

    // Return-to-Zero (RZ) Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            rz_out <= 0;
        end else if (clk_pulse && serial_in) begin
            rz_out <= 1;
        end else begin
            rz_out <= 0;
        end
    end

    // Differential Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            diff_out <= 0;
        end else begin
            diff_out <= serial_in ^ prev_value;
        end
    end

    // Inverted NRZ Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            inv_nrz_out <= 0;
        end else begin
            inv_nrz_out <= ~serial_in;
        end
    end

    // NRZ with Alternating Bit Inversion
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            alt_invert_out <= 0;
            alt_invert_state <= 1;
        end else begin
            alt_invert_out <= (alt_invert_state == 1) ? ~serial_in : serial_in;
            alt_invert_state <= ~alt_invert_state;
        end
    end

    // Parity Bit Output (Odd Parity Calculation)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            parity_out <= 0;
        end else begin
            parity_out <= serial_in ^ (serial_in ^ prev_value);
        end
    end

    // Scrambled NRZ (Simple XOR with a fixed pattern)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            scrambled_out <= 0;
        end else begin
            scrambled_out <= serial_in ^ clk_counter[0];
        end
    end

    // Edge-Triggered NRZ
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            edge_triggered_out <= 0;
        end else begin
            edge_triggered_out <= (serial_in & ~prev_serial_in);
        end
    end

    // Output Multiplexer
    always_comb begin
        serial_out = (mode == 000) ? nrz_out :
                     (mode == 001) ? rz_out :
                     (mode == 010) ? diff_out :
                     (mode == 011) ? inv_nrz_out :
                     (mode == 100) ? serial_in ^ ~prev_value :
                     (mode == 101) ? parity_out :
                     (mode == 110) ? scrambled_out :
                     (mode == 111) ? edge_triggered_out : 0;
    end

endmodule

input.rtl/String_to_ASCII_Converter.sv:
module String_to_ASCII_Converter (
    input wire clk,                       // Clock signal
    input wire reset,                     // Reset signal
    input wire start,                     // Start conversion
    input wire [7:0] char_in [7:0],       // 8-character input string (7 bits per character: 0-95)
    output reg [7:0] ascii_out,           // Final latched ASCII output
    output reg valid,                     // Indicates valid output
    output reg ready                      // Indicates module ready to accept input
);
    // Parameters for character type identification
    localparam DIGIT   = 2'd0;
    localparam UPPER   = 2'd1;
    localparam LOWER   = 2'd2;
    localparam SPECIAL = 2'd3;
    // ASCII Offsets
    localparam DIGIT_OFFSET   = 8'd48;    // '0' = 48
    localparam UPPER_OFFSET   = 8'd65;    // 'A' = 65
    localparam LOWER_OFFSET   = 8'd97;    // 'a' = 97
    localparam SPECIAL_OFFSET = 8'd33;   // First special character '!' = 33
    // Registers
    reg [3:0] index;                      // Index for current character
    reg active;                           // Indicates active conversion
    reg [1:0] char_type;                  // Current character type
    reg [7:0] intermediate_ascii;         // Combinational ASCII value
    // Function to determine character type
    function [1:0] determine_char_type;
        input [7:0] char;
        begin
            if (char < 8'd10)
                determine_char_type = DIGIT;    // '0'-'9'
            else if (char < 8'd36)
                determine_char_type = UPPER;    // 'A'-'Z'
            else if (char < 8'd62)
                determine_char_type = LOWER;    // 'a'-'z'
            else
                determine_char_type = SPECIAL;  // Special characters
        end
    endfunction
    // Combinational logic for ASCII calculation
    always @(*) begin
        // Determine character type
        char_type = determine_char_type(char_in[index]);
        // Calculate ASCII based on character type
        case (char_type)
            DIGIT:   intermediate_ascii = char_in[index] + DIGIT_OFFSET;          // '0'-'9'
            UPPER:   intermediate_ascii = (char_in[index] - 8'd10) + UPPER_OFFSET; // 'A'-'Z'
            LOWER:   intermediate_ascii = (char_in[index] - 8'd36) + LOWER_OFFSET; // 'a'-'z'
            SPECIAL: intermediate_ascii = (char_in[index] - 8'd62) + SPECIAL_OFFSET; // Special characters
            default: intermediate_ascii = 8'd0;
        endcase
    end
    // Sequential logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            index       <= 4'd0;
            ascii_out   <= 8'd0;
            valid       <= 1'b0;
            ready       <= 1'b1;
            active      <= 1'b0;
        end else begin
            if (start && ready) begin
                // Start conversion
                ready <= 1'b0;
                active <= 1'b1;
                index <= 4'd0;
                valid <= 1'b0;
            end else if (active) begin
                // Process current character
                if (index < 8) begin
                    ascii_out <= intermediate_ascii; // Latch current ASCII value
                    valid <= 1'b1; // Indicate valid output
                    index <= index + 1;
                end else begin
                    // Finish conversion
                    active <= 1'b0;
                    ready <= 1'b1;
                    valid <= 1'b0;
                end
            end
        end
    end
endmodule

