module axi_register #(parameter ADDR_WIDTH = 32, DATA_WIDTH = 32) (
    input clk_i,
    input rst_n_i,
    input [ADDR_WIDTH-1:0] awaddr_i,
    input awvalid_i,
    input [DATA_WIDTH-1:0] wdata_i,
    input wvalid_i,
    input [ADDR_WIDTH-1:0] araddr_i,
    input arvalid_i,
    output reg rready_i,
    output reg bready_i,
    output reg [ADDR_WIDTH-1:0] araddr_o,
    output reg awready_o,
    output reg wready_o,
    output reg [1:0] bresp_o,
    output reg bvalid_o,
    output reg rready_o,
    output reg rvalid_o,
    output reg [DATA_WIDTH-1:0] rdata_o,
    output reg [19:0] beat_o,
    output reg start_o,
    output reg writeback_o,
    output reg done_o,
    output reg ID_o
);

    reg [ADDR_WIDTH-1:0] addr_reg [ADDR_WIDTH/8-1:0];
    reg [DATA_WIDTH-1:0] data_reg [ADDR_WIDTH/8-1:0];

    // Initialize registers
    initial begin
        rready_i = 0;
        bready_i = 0;
        rvalid_o = 0;
        awready_o = 0;
        wready_o = 0;
        bresp_o = 2'b00;
        bvalid_o = 0;
        rready_o = 0;
        rvalid_o = 0;
        rdata_o = 0;
        beat_o = 0;
        start_o = 0;
        writeback_o = 0;
        done_o = 1;
        ID_o = 0x0000_0001;
    end

    always @(posedge clk_i or posedge rst_n_i) begin
        if (rst_n_i) begin
            rready_i <= 0;
            bready_i <= 0;
            rvalid_o <= 0;
            awready_o <= 0;
            wready_o <= 0;
            bresp_o <= 2'b00;
            bvalid_o <= 0;
            rready_o <= 0;
            rvalid_o <= 0;
            rdata_o <= 0;
            beat_o <= 0;
            start_o <= 0;
            writeback_o <= 0;
            done_o <= 1;
            ID_o <= 0x0000_0001;
        end else begin
            if (rready_i) begin
                araddr_o <= araddr_i;
                rvalid_o <= arvalid_i;
            end
            if (awready_o && awvalid_i) begin
                addr_reg[araddr_i[ADDR_WIDTH-1:1] - 1] <= awaddr_i;
                awready_o <= 0;
            end
            if (wready_o && wvalid_i) begin
                data_reg[araddr_i[ADDR_WIDTH-1:1] - 1] <= wdata_i;
                wready_o <= 0;
            end
            if (wvalid_i && (wdata_i[ADDR_WIDTH-1] == 1'b1 && wstrb_i)) begin
                if (araddr_i[ADDR_WIDTH-1] == 1'b1) begin
                    beat_o <= wdata_i[20:1];
                    start_o <= 1;
                    writeback_o <= 1;
                end
            end
            if (arready_o && arvalid_i) begin
                raddr_o <= addr_reg[araddr_i[ADDR_WIDTH-1:1] - 1];
                rvalid_o <= 1;
            end
            if (bready_i) begin
                bresp_o <= {bvalid_o, bready_i};
                bvalid_o <= 0;
            end
        end
    end

    // Behavior for read and write transactions
    // ... (Include detailed logic for handling AXI4-Lite transactions as per specification)

endmodule

output.rtl/axis_resize.sv:
module axis_resize (

  input                                           clk,          //Global clock signal: Signals are sampled on the rising edge of clk
  input                                           resetn,       //The global reset signal: resetn is synchronous active-LOW reset.

  input                                           s_valid,      //The s_axis_valid signal indicates that the slave is driving a valid transfer.
  output  reg                                     s_ready,      //The s_axis_ready indicates that the slave can accept a transfer in the current cycle.
  input       [15:0]  s_data,                                   //The s_axis_data is the primary payload data from slave.

  output  reg                                     m_valid,      //The m_axis_valid indicates that the master is driving a valid transfer.
  input                                           m_ready,      //The m_axis_ready indicates that the slave can accept a transfer in the current cycle.
  output  reg [7:0] m_data                                      //The m_axis_data is the primary payload data to master.
);

  // Registers for downscaling
  reg [7:0] downscaled_data;

  // Always block for clocked logic
  always @(posedge clk) begin
    if (!resetn) begin
      s_ready <= 0;
      m_valid <= 0;
      m_data <= 8'b00000000;
      downscaled_data <= 8'b00000000;
    end else begin
      // Downscale the data
      downscaled_data <= s_data[7:0];

      // Set valid signals
      s_ready <= 1;
      m_valid <= 1;
      m_data <= downscaled_data;
    end
  end

endmodule

output.rtl/axis_upscale.sv:
module axis_upscale(
    input clk,
    input resetn,
    input dfmt_enable,
    input dfmt_type,
    input dfmt_se,
    input s_axis_valid,
    input [23:0] s_axis_data,
    output reg m_axis_ready,
    output reg m_axis_valid,
    output [31:0] m_axis_data
);

    // Internal signals
    reg [23:0] upscaled_data;
    reg [31:0] extended_data;

    // Reset condition
    always @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            m_axis_ready <= 0;
            m_axis_valid <= 0;
            m_axis_data <= 32'b0;
        end else begin
            m_axis_ready <= s_axis_valid;
            m_axis_valid <= 1;
        end
    end

    // Data format enable logic
    always @(posedge clk) begin
        if (dfmt_enable) begin
            if (dfmt_type == 1) begin
                upscaled_data <= {upscaled_data, ~s_axis_data[23]};
            end else begin
                upscaled_data <= upscaled_data << 1;
                upscaled_data <= upscaled_data | s_axis_data[23];
            end
        end else begin
            upscaled_data <= s_axis_data;
        end
    end

    // Sign extension logic
    always @(posedge clk) begin
        if (dfmt_se) begin
            extended_data <= {extended_data, s_axis_data[22:1]};
        end else begin
            extended_data <= upscaled_data << 1;
            extended_data <= extended_data | s_axis_data[22];
        end
    end

    // Final data output
    assign m_axis_data = extended_data;

endmodule

