    end else if (inport_arready_o && inport_arvalid_o && outport_arvalid_o) begin
        // Clear read timeout flag on valid read response
        timeout_flag <= 0;
    end
    if (inport_awready_o && inport_awvalid_o && outport_awvalid_o) begin
