module signed_unsigned_comparator #(parameter WIDTH = 5) (
    input [WIDTH-1:0] i_A,
    input [WIDTH-1:0] i_B,
    input i_enable,
    input i_mode,
    output reg o_greater,
    output reg o_less,
    output reg o_equal
);

    // Combinational logic for comparison
    always_comb begin
        if (i_enable) begin
            // Signed mode comparison
            if (i_mode) begin
                o_greater = ((i_A[WIDTH-1] == 1'b0) && i_A > i_B) || ((i_A[WIDTH-1] == 1'b1) && i_A[WIDTH-2:0] > i_B[WIDTH-2:0]);
                o_less = ((i_A[WIDTH-1] == 1'b0) && i_A < i_B) || ((i_A[WIDTH-1] == 1'b1) && i_A[WIDTH-2:0] < i_B[WIDTH-2:0]);
                o_equal = ((i_A[WIDTH-1] == 1'b0) && i_A == i_B) || ((i_A[WIDTH-1] == 1'b1) && i_A[WIDTH-2:0] == i_B[WIDTH-2:0]);
            end
            // Magnitude mode comparison
            else begin
                o_greater = i_A > i_B;
                o_less = i_A < i_B;
                o_equal = i_A == i_B;
            end
        end
        // Disable outputs when i_enable is low
        else begin
            o_greater = 1'b0;
            o_less = 1'b0;
            o_equal = 1'b0;
        end
    end

endmodule

output.rtl/complex_multiplier.sv:
module complex_multiplier (
    input clk,
    input arst_n,
    input [15:0] a_real,
    input [15:0] a_imag,
    input [15:0] b_real,
    input [15:0] b_imag,
    output [31:0] result_real,
    output [31:0] result_imag
);

    reg [31:0] real_result, imag_result;

    // State machine for asynchronous active-low reset
    always @(posedge clk or posedge arst_n) begin
        if (arst_n == 1'b0) begin
            real_result <= 0;
            imag_result <= 0;
        end else if (arst_n == 1'b1) begin
            real_result <= {a_real[15:0], a_real[0]};
            imag_result <= {a_imag[15:0], a_imag[0]};
        end
    end

    // Compute the real and imaginary parts
    always @(posedge clk) begin
        real_result = (a_real * b_real) - (a_imag * b_imag);
        imag_result = (a_real * b_imag) + (a_imag * b_real);
    end

    // Output the results
    assign result_real = real_result;
    assign result_imag = imag_result;

endmodule

output.rtl/compression_engine.sv:
module compression_engine (
  input   logic        clk,
  input   logic        reset,
  input   logic [23:0] num_i,
  output  logic [11:0] mantissa_o,
  output  logic [3:0]  exponent_o
);

  // --------------------------------------------------------
  // Internal wires and registers
  // --------------------------------------------------------
  logic [23:12] exp_oh;         // One-hot encoded exponent
  logic [3:0]   exp_bin;        // Binary exponent
  logic [3:0]   exponent;       // Adjusted exponent
  logic [11:0]  mantissa;       // Mantissa

  // --------------------------------------------------------
  // One-Hot Encoding of the Exponent
  // --------------------------------------------------------
  always @(num_i) begin
    exp_oh[23] = num_i[23];
    for (int i = 23; i >= 0; i--) begin
      exp_oh[i] = num_i[i] & ~|num_i[23:i+1];
    end
  end

  // Use the `onehot_to_bin` module to convert one-hot to binary exponent
  onehot_to_bin #(
    .ONE_HOT_W(12),
    .BIN_W(4)
  ) exp_oh_bin (
    .oh_vec_i(exp_oh),
    .bin_vec_o(exp_bin)
  );

  assign exponent = (|exp_oh) ? exp_bin + 4'h1 : exp_bin;

  // --------------------------------------------------------
  // Mantissa Extraction Logic
  // --------------------------------------------------------
  // Extract the 12-bit mantissa based on `exponent`
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      mantissa_o <= 12'h0;
      exponent_o <= 4'd0;
    end else begin
      if (num_i == 24'h000000) begin
        mantissa_o <= 12'h0;
        exponent_o <= 4'd0;
      end else if (exponent == 4'd0) begin
        mantissa_o <= num_i[11:0];
        exponent_o <= 4'd0;
      end else begin
        mantissa_o <= num_i[exponent-4'd1:exponent-4'd1+11];
        exponent_o <= 4'd0;
      end
    end
  end

endmodule

module onehot_to_bin #(
  parameter ONE_HOT_W = 12,  // Width of the one-hot input
  parameter BIN_W     = 5    // Width of the binary output
)(
  input   wire [ONE_HOT_W-1:0]  oh_vec_i,  // One-hot encoded input
  output  logic [BIN_W-1:0]     bin_vec_o  // Binary encoded output
);

  integer i;

  // Implement priority encoding for the one-hot vector
  assign bin_vec_o = {
    oh_vec_i[11], oh_vec_i[10], oh_vec_i[9], oh_vec_i[8], oh_vec_i[7], oh_vec_i[6], oh_vec_i[5], oh_vec_i[4], oh_vec_i[3], oh_vec_i[2], oh_vec_i[1], oh_vec_i[0]
  };

endmodule

output.rtl/enhanced_fsm_signal_processor.v:
module enhanced_fsm_signal_processor(
    input i_clk,
    input i_rst_n,
    input i_enable,
    input i_clear,
    input i_ack,
    input i_fault,
    input [5:0] i_vector_1,
    input [5:0] i_vector_2,
    input [5:0] i_vector_3,
    input [5:0] i_vector_4,
    input [5:0] i_vector_5,
    input [5:0] i_vector_6,
    output reg o_ready,
    output reg o_error,
    output [2:0] o_fsm_status
);

    // State declaration
    reg [2:0] state_reg;
    reg [31:0] concatenated_vector;
    wire [7:0] o_vector_1_out, o_vector_2_out, o_vector_3_out, o_vector_4_out;

    // State transition logic
    always @(posedge i_clk or posedge i_rst_n) begin
        if (i_rst_n) begin
            state_reg <= 3'b000;
            o_vector_1_out <= 8'b0;
            o_vector_2_out <= 8'b0;
            o_vector_3_out <= 8'b0;
            o_vector_4_out <= 8'b0;
            o_error <= 0;
            o_fsm_status <= 3'b000;
        end else begin
            case (state_reg)
                3'b000: begin
                    if (!i_enable) begin
                        state_reg <= 3'b000;
                    end else if (i_fault) begin
                        state_reg <= 3'b111;
                    end else begin
                        state_reg <= 3'b001;
                    end
                end
                3'b001: begin
                    concatenated_vector <= i_vector_1 << 28 | i_vector_2 << 23 | i_vector_3 << 18 | i_vector_4 << 13 | i_vector_5 << 8 | i_vector_6 << 3;
                    o_vector_1_out <= concatenated_vector[27:20];
                    o_vector_2_out <= concatenated_vector[26:21];
                    o_vector_3_out <= concatenated_vector[25:21];
                    o_vector_4_out <= concatenated_vector[24:21];
                    state_reg <= 3'b010;
                end
                3'b010: begin
                    if (i_ack) begin
                        state_reg <= 3'b000;
                    end else if (i_fault) begin
                        state_reg <= 3'b111;
                    end else begin
                        state_reg <= 3'b010;
                    end
                end
                3'b111: begin
                    o_error <= 1;
                    o_vector_1_out <= 8'b0;
                    o_vector_2_out <= 8'b0;
                    o_vector_3_out <= 8'b0;
                    o_vector_4_out <= 8'b0;
                    state_reg <= 3'b000;
                end
            endcase
        end
    end

    // Output logic
    assign o_ready = (state_reg == 3'b010);
    assign o_vector_1 = o_vector_1_out;
    assign o_vector_2 = o_vector_2_out;
    assign o_vector_3 = o_vector_3_out;
    assign o_vector_4 = o_vector_4_out;

endmodule

output.rtl/low_pass_filter.sv:
module low_pass_filter #(parameter DATA_WIDTH = 16, parameter COEFF_WIDTH = 16, parameter NUM_TAPS = 8)
(
    input clk,
    input reset,
    input [DATA_WIDTH * NUM_TAPS - 1:0] data_in,
    input valid_in,
    input [COEFF_WIDTH * NUM_TAPS - 1:0] coeffs,
    output reg [(DATA_WIDTH + COEFF_WIDTH) + ($clog2(NUM_TAPS)) - 1:0] data_out,
    output reg valid_out
);

    // Internal signal breakdown

    // 2D Internal Representation
    reg [DATA_WIDTH - 1:0] internal_data_in [NUM_TAPS - 1:0];
    reg [COEFF_WIDTH - 1:0] internal_coeffs [NUM_TAPS - 1:0];

    // Register inputs on validity signal
    always @(posedge clk) begin
        if (reset) begin
            internal_data_in <= {DATA_WIDTH{0}};
            internal_coeffs <= {COEFF_WIDTH{0}};
            valid_out <= 1'b0;
        end else if (valid_in) begin
            internal_data_in <= data_in;
            internal_coeffs <= coeffs;
            valid_out <= 1'b1;
        end
    end

    // Convert 1D to 2D for efficient computation
    always @* begin
        internal_data_in = {internal_data_in[NUM_TAPS - 1], internal_data_in[NUM_TAPS - 2]};
        internal_coeffs = {internal_coeffs[NUM_TAPS - 1], internal_coeffs[NUM_TAPS - 2]};
    end

    // Element-wise multiplication and summation
    always @(posedge clk) begin
        if (valid_in) begin
            integer i;
            reg [DATA_WIDTH * COEFF_WIDTH - 1:0] intermediate_sum = 0;
            for (i = 0; i < NUM_TAPS; i = i + 1) begin
                intermediate_sum = intermediate_sum +
                    internal_data_in[NUM_TAPS - i - 1] * internal_coeffs[NUM_TAPS - i - 1];
            end
            data_out <= intermediate_sum;
        end
    end

    // Reset behavior
    always @(posedge clk) begin
        if (reset) begin
            data_out <= {DATA_WIDTH+COEFF_WIDTH{0}};
            valid_out <= 1'b0;
        end
    end

endmodule

output.rtl/decimator_and_peak_detector.sv:
module advanced_decimator_with_adaptive_peak_detection #(parameter DATA_WIDTH = 16, DEC_FACTOR = 4)
(
    input clk,
    input reset,
    input valid_in,
    input [DATA_WIDTH * DEC_FACTOR - 1:0] data_in,
    output reg valid_out,
    output [DATA_WIDTH - 1:0] data_out,
    output [DATA_WIDTH - 1:0] peak_value
);

    reg [DATA_WIDTH - 1:0] decimated_data [DEC_FACTOR - 1:0];
    reg [DATA_WIDTH - 1:0] peak_temp;

    // Input Data Registering
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            decimated_data <= {DATA_WIDTH{1'b0}};
            peak_temp <= data_in[0];
            valid_out <= 1;
        end else if (valid_in) begin
            decimated_data <= {data_in[DATA_WIDTH*(DEC_FACTOR-1)+:DATA_WIDTH]};
            peak_temp <= decimated_data[0];
            valid_out <= 1;
        end else begin
            peak_temp <= 1'b0;
            valid_out <= 0;
        end
    end

    // Decimation
    always @(posedge clk) begin
        if (valid_out) begin
            decimated_data[0] <= data_in[DATA_WIDTH*(DEC_FACTOR-1)+:DATA_WIDTH];
            for (int i = 1; i < DEC_FACTOR; i++) begin
                decimated_data[i] <= data_in[(i-1)*DATA_WIDTH +: DATA_WIDTH];
            end
        end
    end

    // Peak Detection
    always @(posedge clk) begin
        if (valid_out) begin
            peak_temp = decimated_data[0];
            for (int i = 1; i < DEC_FACTOR; i++) begin
                if (decimated_data[i] > peak_temp) begin
                    peak_temp = decimated_data[i];
                end
            end
        end
    end

    // Output Packing
    always @(posedge clk) begin
        if (valid_out) begin
            data_out = decimated_data[DEC_FACTOR - 1];
            peak_value = peak_temp;
        end
    end

endmodule

output.rtl/sgd_linear_regression.sv:
module sgd_linear_regression #(
    parameter DATA_WIDTH = 16, 
    parameter LEARNING_RATE = 3'd1
) (
    input  logic clk,                               // Clock
    input  logic reset,                             // Asynchronous reset
    input  logic signed [DATA_WIDTH-1:0] x_in,      // Input data (x)
    input  logic signed [DATA_WIDTH-1:0] y_true,    // True output (target)
    output logic signed [DATA_WIDTH-1:0] w,     // Trained weight
    output logic signed [DATA_WIDTH-1:0] b      // Trained bias
);
    localparam NBW_PRED  = 2*DATA_WIDTH + 1;
    localparam NBW_ERROR = NBW_PRED + 1;
    localparam NBW_DELTA = 3 + NBW_ERROR + DATA_WIDTH;

    // Intermediate values
    logic signed [NBW_PRED-1:0] y_pred;  
    logic signed [NBW_ERROR-1:0] error;  
    logic signed [NBW_DELTA-1:0] delta_w; 
    logic signed [NBW_DELTA-1:0] delta_b;

    // Predicted output calculation
    always_comb begin
      y_pred = (w * x_in) + b;
    end

    // Error calculation
    always_comb begin
      error = y_true - y_pred;
    end

    // Weight and bias updates
    always_comb begin
      delta_w = LEARNING_RATE * error * x_in;
      delta_b = LEARNING_RATE * error;
    end

    // Weight and bias adjustment
    always_ff begin : weight_bias_update
      if (reset) begin
        w = 0;
        b = 0;
      end else begin
        w = w + delta_w;
        b = b + delta_b;
      end
    end

endmodule

output.rtl/fsm_linear_reg.sv:
module fsm_linear_reg #(parameter DATA_WIDTH = 16) (
    input clk,
    input reset,
    input start,
    input [DATA_WIDTH-1:0] x_in,
    input [DATA_WIDTH-1:0] w_in,
    input [DATA_WIDTH-1:0] b_in,
    output reg [2*DATA_WIDTH-1:0] result1,
    output reg [DATA_WIDTH:0] result2,
    output reg done
);

    // State declarations
    typedef enum logic [1:0] (IDLE, COMPUTE, DONE);
    typedef logic [1:0] state_t;
    logic [1:0] current_state, next_state;

    // State transition logic
    always_comb begin
        case (current_state)
            IDLE:
                if (start) begin
                    next_state = COMPUTE;
                    result1 <= 0;
                    result2 <= 0;
                end else begin
                    next_state = IDLE;
                end
            COMPUTE:
                result1 <= (w_in * x_in) >>> 1;
                result2 <= b_in + (x_in >>> 2);
                next_state = DONE;
                done <= 1;
            DONE:
                done <= 0;
                next_state = IDLE;
                result1 <= 0;
                result2 <= 0;
        endcase
    end

    // State machine
    always_ff @(posedge clk or posedge reset) begin
        if (reset) current_state <= IDLE;
        else current_state <= next_state;
    end

endmodule

