module data_width_converter(
    input clk,
    input reset,
    input [31:0] data_in,
    input data_valid,
    output reg [127:0] o_data_out,
    output reg o_data_out_valid
);
    // Internal state
    reg [3:0] input_count = 0;
    reg [127:0] output_buffer = {32'b0};

    // Counter to track valid inputs
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            input_count <= 0;
            output_buffer <= {32'b0};
        end else begin
            if (data_valid && input_count == 0) begin
                output_buffer <= data_in;
                input_count <= 1;
            end else if (data_valid && input_count < 4) begin
                output_buffer <= {output_buffer{data_in}};
                input_count <= input_count + 1;
            end

            // Generate output after four valid inputs
            if (input_count == 4) begin
                o_data_out <= output_buffer;
                o_data_out_valid <= 1;
                input_count <= 0; // Reset counter
            end
        end
    end
endmodule

output.rtl/dbi_enc.sv:
module dbi_enc(
    input [39:0] data_in,
    input clk,
    input rst_n,
    output reg [39:0] data_out,
    output reg [1:0] dbi_cntrl
);

    reg [39:0] prev_data_g1, prev_data_g0;

    initial begin
        dbi_cntrl <= 2'b00;
        data_out <= 40'h0000_0000;
        prev_data_g1 <= 40'h0000_0000;
        prev_data_g0 <= 40'h0000_0000;
    end

    always @(posedge clk) begin
        if (rst_n) begin
            prev_data_g1 <= 40'h0000_0000;
            prev_data_g0 <= 40'h0000_0000;
            data_out <= 40'h0000_0000;
            dbi_cntrl <= 2'b00;
        end else begin
            prev_data_g1 <= data_in[39:20];
            prev_data_g0 <= data_in[19:0];

            dbi_cntrl[1] = (data_in[39:20] != prev_data_g1) && (data_in[39:20] != 40'h0000_0000);
            dbi_cntrl[0] = (data_in[19:0] != prev_data_g0) && (data_in[19:0] != 40'h0000_0000);

            if (dbi_cntrl[1]) begin
                data_out[39:20] = ~data_in[39:20];
            end
            if (dbi_cntrl[0]) begin
                data_out[19:0] = ~data_in[19:0];
            end
        end
    end

endmodule

output.rtl/dbi_dec.sv:
module dbi_dec (
   input  wire        rst_n,     // Asynchronous reset
   input  wire        clk,       // Clock
   input  wire [39:0] data_in,   // Data input before DBI decoder logic
   input  wire [1:0]  dbi_cntrl, // Indicate data inversion enabled for each group 
   output wire [39:0] data_out   // Output data after DBI logic
);

   // Internal flip-flops to hold the decoded data
   reg [39:0] group_0, group_1;

   // Always block for clocked logic
   always @(posedge clk) begin
      if (!rst_n) begin
         group_0 <= 40'b0;
         group_1 <= 40'b0;
         data_out <= group_0;
      end else begin
         // Split data_in into two groups
         group_0 <= data_in[39:20];
         group_1 <= data_in[19:0];

         // Apply DBI decoding based on dbi_cntrl
         data_out <= (dbi_cntrl == 2'b00) ? group_0 : (dbi_cntrl == 2'b01) ? group_1 : group_0 | group_1;
      end
   end

endmodule

output.rtl/cvdp_copilot_decode_firstbit.sv:
module first_bit_decoder #(
    parameter IN_WIDTH_g = 32,
    parameter IN_REG_g = 1,
    parameter OUT_REG_g = 1,
    parameter PLREGS_g = 1
) (
    input [IN_WIDTH_g-1:0] In_Data,
    input In_Valid,
    input Clk,
    input Rst,
    output reg [$clog2(IN_WIDTH_g)-1:0] Out_FirstBit,
    output reg Out_Found,
    output reg Out_Valid
);

    // Internal variables
    reg [IN_WIDTH_g-1:0] internal_data;
    reg [$clog2(IN_WIDTH_g)-1:0] found_bit;
    reg [$clog2(IN_WIDTH_g)-1:0] stage_output;

    // Pipeline registers
    reg [$clog2(IN_WIDTH_g)-1:0] pipelined_data [PLREGS_g-1:0];

    // Initialize pipeline registers
    initial begin
        if (Rst) begin
            internal_data = 0;
            found_bit = 0;
            pipelined_data = {{IN_WIDTH_g{1'b0}}} << PLREGS_g;
        end
        else begin
            internal_data = In_Data;
            found_bit = In_Valid ? 1'b1 : 1'b0;
            pipelined_data = {internal_data, {1'b0}} << PLREGS_g;
        end
    end

    // Pipeline logic
    always @(posedge Clk or negedge Clk or Rst) begin
        if (Rst) begin
            Out_FirstBit <= 0;
            Out_Found <= 0;
            Out_Valid <= 0;
        end else begin
            pipelined_data[PLREGS_g-1] <= internal_data;
            for (int i = PLREGS_g-2 downto 0) begin
                pipelined_data[i] <= pipelined_data[i+1];
            end
            internal_data <= pipelined_data[0];

            if (internal_data[IN_WIDTH_g-1]) begin
                found_bit <= IN_WIDTH_g-1;
                Out_FirstBit <= found_bit;
                Out_Valid <= 1;
                Out_Found <= 1;
            end
            else begin
                Out_FirstBit <= 0;
                Out_Found <= 0;
                Out_Valid <= 0;
            end
        end
    end

endmodule

