module fibonacci_series (
    input clk,
    input rst,
    output reg [31:0] fib_out,
    output reg overflow_flag
);

    reg [31:0] RegA = 0;
    reg [31:0] RegB = 1;
    reg [31:0] next_fib;
    reg overflow_detected = 0;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            RegA <= 0;
            RegB <= 1;
            fib_out <= 0;
            overflow_flag <= 0;
            overflow_detected <= 0;
        end else begin
            next_fib <= RegA + RegB;
            if (next_fib[31] == 1) begin
                overflow_detected <= 1;
                fib_out <= RegB;
                overflow_flag <= 1;
            end else begin
                RegA <= RegB;
                RegB <= next_fib;
                fib_out <= RegB;
            end
        end
    end
endmodule

output.rtl/fifo_async.sv:
module fifo_async #(
    parameter DATA_WIDTH = 8,
    parameter DEPTH = 16
)(
    input wire w_clk,
    input wire w_rst,
    input wire w_inc,
    input wire [DATA_WIDTH-1:0] w_data,
    input wire r_clk,
    input wire r_rst,
    input wire r_inc,
    output reg w_full,
    output reg r_empty,
    output reg [DATA_WIDTH-1:0] r_data
);

    reg [DATA_WIDTH-1:0] write_ptr;
    reg [DATA_WIDTH-1:0] read_ptr;
    wire sync_w_rst, sync_r_rst;
    wire sync_w_clk, sync_r_clk;

    // Cross-clock synchronizers
    always @(posedge sync_w_clk) begin
        sync_r_rst <= w_rst;
        write_ptr <= 0;
    end
    always @(posedge sync_r_clk) begin
        sync_w_rst <= r_rst;
        read_ptr <= 0;
    end

    // Gray counter for write pointer
    always @(posedge w_clk) begin
        if (w_inc) begin
            if (write_ptr == DEPTH-1) begin
                write_ptr <= 0;
            end else begin
                write_ptr <= write_ptr + 1;
            end
        end
    end

    // Gray counter for read pointer
    always @(posedge r_clk) begin
        if (r_inc) begin
            if (read_ptr == 0) begin
                read_ptr <= DEPTH-1;
            end else begin
                read_ptr <= read_ptr - 1;
            end
        end
    end

    // Output flags
    assign w_full = (write_ptr == read_ptr);
    assign r_empty = (write_ptr == read_ptr);

    // FIFO read and write logic
    assign r_data = (read_ptr != DEPTH) ? read_mem[read_ptr] : 1'bz;

    // FIFO memory
    reg [DATA_WIDTH-1:0] read_mem [DEPTH-1:0];

    always @(posedge sync_w_clk) begin
        if (sync_r_rst) begin
            read_mem[read_ptr] <= 1'bz;
        end else if (w_inc) begin
            if (write_ptr < DEPTH-1) begin
                read_mem[read_ptr] <= w_data;
                write_ptr <= write_ptr + 1;
            end
        end
    end

    always @(posedge sync_r_clk) begin
        if (sync_w_rst) begin
            read_mem[read_ptr] <= 1'bz;
        end else if (r_inc) begin
            if (read_ptr > 0) begin
                r_data <= read_mem[read_ptr - 1];
                read_ptr <= read_ptr - 1;
            end
        end
    end

endmodule

output.rtl/ping_pong_fifo_2_axi_stream.sv:
module ping_pong_fifo_2_axi_stream #(
  parameter logic                              DATA_WIDTH          = 24,
  parameter logic                              STROBE_WIDTH        = DATA_WIDTH / 8,
  parameter logic                              USE_KEEP            = 0,
  parameter logic                              USER_IN_DATA        = 1
)(
  input  logic                                 rst,

  // Ping Pong FIFO Read Interface
  input  logic                                 i_block_fifo_rdy,
  output logic                                 o_block_fifo_act,
  input  logic [23:0]                          i_block_fifo_size,
  input  logic [(DATA_WIDTH + 1) - 1:0]        i_block_fifo_data,
  output logic                                 o_block_fifo_stb,
  input  logic [3:0]                           i_axi_user,

  // AXI Stream Output
  input  logic                                 i_axi_clk,
  output logic [3:0]                           o_axi_user,
  input  logic                                 i_axi_ready,
  output logic [DATA_WIDTH - 1:0]              o_axi_data,
  output logic                                 o_axi_last,
  output logic                                 o_axi_valid
);

// Internal signals
logic [DATA_WIDTH - 1:0] fifo_data_buffer;
logic fifo_valid_buffer;
logic fifo_last_buffer;

// Reset Condition
always_ff @(posedge i_axi_clk or posedge rst) begin
  if (rst) begin
    o_block_fifo_act   <= 1'b0;
    o_axi_valid        <= 1'b0;
    fifo_data_buffer   <= {DATA_WIDTH{1'b0}};
    fifo_valid_buffer  <= 1'b0;
    fifo_last_buffer   <= 1'b0;
  end else begin
    // FIFO Read Logic
    if (i_block_fifo_rdy && i_block_fifo_stb) begin
      fifo_data_buffer <= i_block_fifo_data;
      fifo_valid_buffer <= 1'b1;
      fifo_last_buffer   <= i_block_fifo_last;
    end

    // AXI Stream Logic
    if (i_axi_ready && fifo_valid_buffer) begin
      o_axi_data <= fifo_data_buffer;
      o_axi_last <= fifo_last_buffer;
      o_axi_valid <= 1'b1;
    end
  end
end
endmodule

input.rtl/ping_pong_fifo_2_axi_stream.sv:
module ping_pong_fifo_2_axi_stream #( 
    parameter DATA_WIDTH = 32
)(
    input  logic                                 rst,

    // Ping Pong FIFO Read Interface
    input  logic                                 i_block_fifo_rdy,
    output logic                                 o_block_fifo_act,
    input  logic [23:0]                          i_block_fifo_size,
    input  logic [(DATA_WIDTH + 1) - 1:0]        i_block_fifo_data,
    output logic                                 o_block_fifo_stb,
    input  logic [3:0]                           i_axi_user,

    // AXI Stream Output
    input  logic                                 i_axi_clk,
    output logic [3:0]                           o_axi_user,
    input  logic                                 i_axi_ready,
    output logic [DATA_WIDTH - 1:0]              o_axi_data,
    output logic                                 o_axi_last,
    output logic                                 o_axi_valid
);

    // Internal Registers
    logic [23:0] block_size_reg;
    logic [23:0] data_count;
    logic        fifo_active;
    logic        data_valid;

    typedef enum logic [1:0] {
        IDLE,
        READ_FIFO,
        SEND_AXI
    } state_t;

    state_t current_state, next_state;

    always_ff @(posedge i_axi_clk or posedge rst) begin
        if (rst) begin
            current_state      <= IDLE;
            block_size_reg     <= 24'd0;
            data_count         <= 24'd0;
            fifo_active        <= 1'b0;
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_data         <= {DATA_WIDTH{1'b0}};
            o_axi_last         <= 1'b0;
            o_axi_user         <= 4'd0;
        end else begin
            current_state      <= next_state;
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_last         <= 1'b0;

            case (current_state)
                IDLE: begin
                    if (i_block_fifo_rdy) begin
                        o_block_fifo_act <= 1'b1; 
                        block_size_reg    <= i_block_fifo_size;
                        fifo_active       <= 1'b1;
                        data_count        <= 24'd0;
                        next_state        <= READ_FIFO;
                    end else begin
                        next_state <= IDLE;
                    end
                end

                READ_FIFO: begin
                    if (fifo_active && i_block_fifo_rdy) begin
                        o_block_fifo_stb <= 1'b1; 
                        data_count       <= data_count + 24'd1;
                        next_state       <= SEND_AXI;
                    end else begin
                        next_state <= READ_FIFO;
                    end
                end

                SEND_AXI: begin
                    if (fifo_active && i_axi_ready) begin
                        o_axi_valid  <= 1'b1;
                        o_axi_data   <= i_block_fifo_data[DATA_WIDTH-1:0];
                        o_axi_user   <= i_axi_user;

                        if (data_count + 24'd1 >= block_size_reg) begin
                            o_axi_last <= 1'b1;
                            fifo_active <= 1'b0; 
                            next_state  <= IDLE;
                        end else begin
                            next_state <= READ_FIFO;
                        end
                    end else begin
                        next_state <= SEND_AXI;
                    end
                end

                default: next_state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/ping_pong_fifo_2_axi_stream.sv:
module ping_pong_fifo_2_axi_stream #( 
    parameter DATA_WIDTH = 32
)(
    input  logic                                 rst,
    input  logic                                 i_flush,
    input  logic                                 i_pause,
    input  logic                                 i_block_fifo_rdy,
    input  logic [23:0]                          i_block_fifo_size,
    input  logic [(DATA_WIDTH + 1) - 1:0]        i_block_fifo_data,
    input  logic [(DATA_WIDTH + 1) - 1:0]        i_axi_user,
    input  logic                                 i_axi_clk,
    input  logic                                 i_axi_ready,
    output logic [DATA_WIDTH - 1:0]              o_axi_data,
    output logic                                 o_axi_valid,
    output logic                                 o_axi_last,
    output logic                                 o_block_fifo_act,
    output logic                                 o_block_fifo_stb
);

    // Internal Registers
    logic [23:0] block_size_reg;
    logic [23:0] data_count;
    logic        fifo_active;
    logic        fifo_data_valid;
    logic        data_pending;
    logic        fifo_data_reg;

    typedef enum logic [1:0] {
        IDLE,
        READ_FIFO,
        SEND_AXI,
        FLUSH
    } state_t;

    state_t current_state, next_state;

    always_ff @(posedge i_axi_clk or posedge rst) begin
        if (rst) begin
            current_state      <= IDLE;
            block_size_reg     <= 24'd0;
            data_count         <= 24'd0;
            fifo_active        <= 1'b0;
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_data         <= {DATA_WIDTH{1'b0}};
            o_axi_last         <= 1'b0;
            o_axi_user         <= 4'd0;
            data_pending       <= 1'b0;
            fifo_data_valid    <= 1'b0;
            fifo_data_reg      <= 0;
        end else begin
            current_state      <= next_state;
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_data         <= {DATA_WIDTH{1'b0}};
            o_axi_last         <= 1'b0;

            case (current_state)
                IDLE: begin
                    if (i_flush) begin
                        next_state <= FLUSH;
                    end else begin
                        if (i_block_fifo_rdy) begin
                            o_block_fifo_act <= 1'b1; 
                            block_size_reg    <= i_block_fifo_size;
                            data_count        <= 24'd0;
                            fifo_active       <= 1'b1;
                            next_state        <= READ_FIFO;
                        end else begin
                            next_state <= IDLE;
                        end
                    end
                end

                READ_FIFO: begin
                    if (fifo_active && i_block_fifo_rdy) begin
                        o_block_fifo_stb <= 1'b1; 
                        data_count       <= data_count + 24'd1;
                        if (data_count >= block_size_reg) begin
                            fifo_active <= 1'b0; 
                            next_state <= IDLE;
                        end else begin
                            next_state <= READ_FIFO;
                        end
                    end else begin
                        next_state <= READ_FIFO;
                    end
                end

                SEND_AXI: begin
                    if (fifo_active && i_axi_ready && !i_pause) begin
                        o_axi_valid  <= 1'b1;
                        o_axi_data   <= i_block_fifo_data[DATA_WIDTH-1:0];
                        o_axi_last   <= 1'b1;
                        fifo_active  <= 1'b0; 
                        next_state   <= IDLE;
                    end else if (fifo_active && i_axi_ready && i_pause) begin
                        next_state <= SEND_AXI;
                    end else begin
                        next_state <= SEND_AXI;
                    end
                end

                FLUSH: begin
                    if (i_flush) begin
                        block_size_reg <= 24'd0;
                        data_count         <= 24'd0;
                        fifo_active        <= 1'b0;
                        fifo_data_valid    <= 1'b0;
                        fifo_data_reg      <= 0;
                        o_block_fifo_act <= 1'b0;
                        o_block_fifo_stb <= 1'b0;
                        o_axi_valid        <= 1'b0;
                        o_axi_data         <= {DATA_WIDTH{1'b0}};
                        o_axi_last         <= 1'b0;
                    end
                end

                default: next_state <= IDLE;
            endcase
        end
    end
endmodule

output.rtl/FILO_RTL.sv:
module FILO_RTL #(parameter DATA_WIDTH = 8, parameter FILO_DEPTH = 16) (
    input clk,
    input reset,
    input push,
    input pop,
    input [DATA_WIDTH-1:0] data_in,
    output reg [DATA_WIDTH-1:0] data_out,
    output reg full,
    output reg empty
);

    reg [DATA_WIDTH-1:0] fifo_data[FILO_DEPTH-1:0];
    integer top = 0;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            top <= 0;
            full <= 0;
            empty <= 1;
            data_out <= {DATA_WIDTH{1'b0}};
        end else if (push) begin
            if (top < FILO_DEPTH - 1) begin
                fifo_data[top] <= data_in;
                top <= top + 1;
                full <= 0;
                empty <= 0;
            end
        end else if (pop) begin
            if (top > 0) begin
                data_out <= fifo_data[top - 1];
                top <= top - 1;
                full <= 0;
                empty <= 0;
            end else begin
                full <= 1;
                empty <= 1;
                data_out <= {DATA_WIDTH{1'b0}}; // Feedthrough case
            end
        end
    end

endmodule

input.rtl/FILO_RTL.sv:
module FILO_RTL #(
    parameter DATA_WIDTH = 8,  // Width of the data entries
    parameter FILO_DEPTH = 16  // Depth of the FILO buffer
) (
    input  wire                  clk,       // Clock signal
    input  wire                  reset,     // Asynchronous reset signal
    input  wire                  push,      // Push control signal
    input  wire                  pop,       // Pop control signal
    input  wire [DATA_WIDTH-1:0] data_in,   // Data input
    output reg  [DATA_WIDTH-1:0] data_out,  // Data output
    output reg                   full,      // Full status signal
    output reg                   empty      // Empty status signal
);


  reg [DATA_WIDTH-1:0] memory[FILO_DEPTH-1:0];  
  reg [$clog2(FILO_DEPTH):0] top;  

  reg feedthrough_valid;
  reg [DATA_WIDTH-1:0] feedthrough_data;


  always @(posedge clk or posedge reset) begin
    if (reset) begin
      top <= 0;
      empty <= 1;
      full <= 0;
      feedthrough_valid <= 0;
      data_out <= 0;  
    end else begin

      if (push && pop && empty) begin
        data_out <= data_in; 
        feedthrough_data <= data_in;
        feedthrough_valid <= 1;
      end else begin

        if (push && !full) begin
          memory[top] <= data_in;  
          top <= top + 1;  
          feedthrough_valid <= 0;
        end

        if (pop && !empty) begin
          if (feedthrough_valid) begin
            data_out <= feedthrough_data;  
            feedthrough_valid <= 0;
          end else begin
            top <= top; 
            data_out <= memory[top-1]; 
          end
        end
      end

      empty <= (top == 0);
      full  <= (top == FILO_DEPTH);  
    end
  end
endmodule

