output.rtl/hamming_code_tx_for_4bit.sv:
module hamming_code_tx_for_4bit (
    input [3:0] data_in,
    output reg [7:0] data_out
);

    // Step 1: Set the least significant bit to 0
    assign data_out[0] = 0;

    // Step 2: Calculate parity bit for positions 0, 1, 3
    assign data_out[1] = (data_in[0] ^ data_in[1] ^ data_in[3]) | 1;

    // Step 3: Calculate parity bit for positions 0, 2, 3
    assign data_out[2] = (data_in[0] ^ data_in[2] ^ data_in[3]) | 1;

    // Step 4: Calculate parity bit for positions 1, 2, 3
    assign data_out[4] = (data_in[1] ^ data_in[2] ^ data_in[3]) | 1;

    // Step 5: Assign the original data bits in order
    assign data_out[3] = data_in[0];
    assign data_out[5] = data_in[1];
    assign data_out[6] = data_in[2];
    assign data_out[7] = data_in[3];

endmodule

output.rtl/hamming_code_receiver.sv:
module hamming_code_receiver(
    input [7:0] data_in,
    output reg [3:0] data_out
);

    // Syndrome bits for error detection
    logic c1, c2, c3;

    // Error detection logic
    always_comb begin
        c3 = data_in[1] ^ data_in[3] ^ data_in[5] ^ data_in[7];
        c2 = data_in[2] ^ data_in[3] ^ data_in[6] ^ data_in[7];
        c1 = data_in[4] ^ data_in[5] ^ data_in[6] ^ data_in[7];
    end

    // Error correction logic
    always_comb begin
        if ({c1, c2, c3} == 3'b000) begin
            // No error detected
            data_out = data_in;
        end else begin
            // Single-bit error detected, correct it
            case ({c1, c2, c3})
                3'b001: data_out = {data_in[6], data_in[6], data_in[6], data_in[6]};
                3'b010: data_out = {data_in[5], data_in[5], data_in[5], data_in[5]};
                3'b011: data_out = {data_in[4], data_in[4], data_in[4], data_in[4]};
                3'b100: data_out = {data_in[3], data_in[3], data_in[3], data_in[3]};
                3'b101: data_out = {data_in[2], data_in[2], data_in[2], data_in[2]};
                3'b110: data_out = {data_in[1], data_in[1], data_in[1], data_in[1]};
            endcase
        end
    end

endmodule

input.rtl/hamming_tx.sv:
module hamming_code_tx_for_4bit( 
  input[3:0] data_in,
  output[7:0] data_out
);
  assign data_out[0] = 1'b0;
  assign data_out[1] = data_in[0] ^ data_in[1] ^ data_in[3]; // 2^0
  assign data_out[2] = data_in[0] ^ data_in[2] ^ data_in[3]; // 2^1
  assign data_out[3] = data_in[0];
  assign data_out[4] = data_in[1] ^ data_in[2] ^ data_in[3]; // 2^2
  assign data_out[5] = data_in[1];
  assign data_out[6] = data_in[2];
  assign data_out[7] = data_in[3];
endmodule

output.rtl/hamming_tx.sv:
module hamming_tx #(parameter DATA_WIDTH = 4, PARITY_BIT = 3) (
    input [DATA_WIDTH-1:0] data_in,
    output [ENCODED_DATA-1:0] data_out
);
    logic [PARITY_BIT-1:0] parity;

    // Initialize parity to zero
    initial begin
        parity = '{1'b0, 1'b0, 1'b0, 1'b0};
    end

    // Step 2: Assign data_in to data_out
    assign data_out = '{1'b0, data_in[DATA_WIDTH-1], data_in[DATA_WIDTH-2], data_in[DATA_WIDTH-3], parity[0], parity[1], parity[2], 1'b0};

    // Step 3: Calculate the even parity bits based on the Hamming code principle
    always @* begin
        for (int i = 0; i < PARITY_BIT; i = i + 1) begin
            parity[i] = (data_out[2**i] ^ data_out[2**i + 1] ^ data_out[2**i + 2] ^ data_out[2**i + 3]) & 1'b1;
        end
    end

endmodule

// ENCODED_DATA and ENCODED_DATA_BIT are not directly set within the module.
// They should be calculated based on the DATA_WIDTH and PARITY_BIT parameters.
// For example, ENCODED_DATA = DATA_WIDTH + PARITY_BIT + 1
// ENCODED_DATA_BIT = ceil(log2(ENCODED_DATA))

// Example instantiation in a top-level design:
// hamming_tx #(.DATA_WIDTH(4), .PARITY_BIT(3)) hamming_tx_inst (
//     .data_in(data_in),
//     .data_out(data_out)
// );

input.rtl/hamming_rx.sv:
module hamming_code_receiver (
  input[7:0] data_in,
  output [3:0] data_out
);

  wire c1,c2,c3,error;
  reg[7:0] correct_data;


  assign c3 =  data_in[1] ^ data_in[3] ^ data_in[5] ^ data_in[7];
  assign c2 =  data_in[2] ^ data_in[3] ^ data_in[6] ^ data_in[7];
  assign c1 =  data_in[4] ^ data_in[5] ^ data_in[6] ^ data_in[7];

  assign error = ({c3,c2,c1}==3'b000) ? 1'b0 : 1'b1;

  always@(*)
  begin
    correct_data = 0;
    if(error)
    begin
      correct_data             = data_in;
      correct_data[{c1,c2,c3}] = ~correct_data[{c1,c2,c3}];
    end
    else
    begin
      correct_data             = data_in;
    end
  end

 assign data_out = {correct_data[7],correct_data[6],correct_data[5],correct_data[3]};

endmodule

