   always_comb begin
        next_state = present_state;

     case(present_state)
             S0  : begin 
                      if(start)
                         next_state = S1;
                      else
                         next_state = S0;
                   end
             S1  : begin 
                         next_state = S2;
                   end
             S2  : begin 
                      if(iteration == 0)
                        next_state = S3;
                     else if(iteration == 1)
                        next_state = S4;
                     else if(iteration == 2)
                        next_state = S5;
                     else 
                        next_state = S6;
                   end
             S3  : begin 
                         next_state = S7;

                   end
             S4  : begin 
                         next_state = S7;
                  end
             S5  : begin 
                         next_state = S7;
                  end
             S6  : begin 
                         next_state = S7;
                  end
             S7  :begin
                         next_state = S8;
                  end
             S8  : begin
                         next_state = S9;
                  end
             S9  : begin
                      if(iteration < 4)
                         next_state = S1;
                      else
                         next_state = S10;
                   end
             S10 : begin
                      next_state = S0;
                   end
             default : ;
     endcase
   end 

   always_comb begin

      case(present_state)
             S0 : begin
                    clr_en = 1;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en   = 0;
                    iteration = 0;
                    target = target + 4'h0;
                  end 
             S1 : begin
                    clr_en = 0;
                    cap_en = 1;
                    delta_en = 0;
                    sum_en = 0;  
                    iteration = iteration + 0;  
                    target = target + 4'h0;              
                  end
             S2 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0; 
                    iteration = iteration + 0;     
                    target = target + 4'h0;              
                  end
             S3 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t1;
                  end
             S4 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t2;
                  end     

             S5 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t3;
                  end  
             S6 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t4;
                  end        
             S7 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 1;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end
             S8 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 1;
                    iteration = iteration + 1;
                    target = target + 4'h0;
                  end
             S9 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end  
             S10 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end



           default : begin
                      clr_en = 0;
                      cap_en = 0;
                      delta_en = 0;
                      sum_en = 0;
                      iteration = 0;
                      target = target + 4'h0;
                     end
       endcase
   end
   assign w1 = w1_reg;
   assign w2 = w2_reg;
   assign bias = bias_reg;

endmodule

module gate_target(
   input  logic        [1:0] gate_select,
   output logic signed [3:0] o_1,
   output logic signed [3:0] o_2,
   output logic signed [3:0] o_3,
   output logic signed [3:0] o_4
);
   always_comb begin
     case(gate_select)
          2'b00 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
          2'b01 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b10 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b11 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
        default : begin
                    o_1 =  0; 
                    o_2 =  0; 
                    o_3 =  0; 
                    o_4 =  0; 
                  end
        endcase
   end
endmodule

module hebbian_rule #(
    parameter NUM_INPUTS = 2,
    parameter NUM_OUTPUTS = 1,
    parameter NUM_STATES = 11
)(
    input clk,
    input rst,
    input start,
    input [NUM_INPUTS-1:0] a,
    input [NUM_INPUTS-1:0] b,
    input [1:0] gate_select,
    output reg [NUM_OUTPUTS-1:0] w1,
    output reg [NUM_OUTPUTS-1:0] w2,
    output reg [NUM_OUTPUTS-1:0] bias,
    output reg [NUM_STATES-1:0] present_state,
    output reg [NUM_STATES-1:0] next_state
);

    // FSM state register
    reg [NUM_STATES-1:0] fsm_state = 0;

    // Registers for input vectors
    reg [NUM_INPUTS-1:0] x1, x2;

    // Registers for target values
    reg [NUM_OUTPUTS-1:0] target;

    // Weight and bias registers
    reg [NUM_OUTPUTS-1:0] weights [NUM_INPUTS-1:0];
    reg [NUM_OUTPUTS-1:0] bias_reg;

    // Gate target submodule
    logic [NUM_OUTPUTS-1:0] gate_target[NUM_GATES-1:0];

    // State transition logic
    always @(posedge clk or posedge rst) begin
        if (rst)
            fsm_state <= 0;
        else if (start)
            fsm_state <= 1;
        else
            case (fsm_state)
                0: // Reset
                    present_state <= 0;
                    next_state <= 0;
                1: // Capture inputs
                    x1 <= a;
                    x2 <= b;
                    next_state <= 2;
                2: // Assign target based on gate_select
                    case (gate_select)
                        2'b00: target = x1 & x2; // AND gate
                        2'b01: target = x1 | x2; // OR gate
                        2'b10: target = ~(x1 & x2); // NAND gate
                        2'b11: target = ~(x1 | x2); // NOR gate
                        default: target = x1;
                    endcase
                    next_state <= 3;
                3: // Compute deltas for weights and bias
                    weights[0] <= x1 * target;
                    weights[1] <= x2 * target;
                    bias_reg <= target;
                    next_state <= 4;
                4: // Update weights and bias
                    w1 <= weights[0] + w1;
                    w2 <= weights[1] + w2;
                    bias <= bias_reg + bias;
                    next_state <= 5;
                5: // Loop through training iterations
                    next_state <= 6;
                6: // Return to initial state
                    present_state <= 0;
                    next_state <= 0;
                    default: next_state <= 0;
            endcase
    end

endmodule

output.rtl/hill_cipher.sv:
module hill_cipher #(parameter BLOCK_SIZE = 3, KEY_BITS = 5) (
    input wire clk,
    input wire reset,
    input wire start,
    input wire [14:0] plaintext,
    input wire [44:0] key,
    output reg [14:0] ciphertext,
    output reg done
);

// Define the key matrix size based on KEY_BITS
parameter K_SIZE = BLOCK_SIZE * KEY_BITS / 8;

// State register
reg [K_SIZE - 1:0] state;

// Local variables
wire [K_SIZE - 1:0] key_matrix[0:K_SIZE-1];
wire [BLOCK_SIZE - 1:0] plaintext_vector[0:K_SIZE-1];
wire [BLOCK_SIZE - 1:0] ciphertext_vector[0:K_SIZE-1];

// Key matrix initialization
initial begin
    key_matrix[0] = {key[44-1:44], key[40-1:40], key[35-1:35]};
    key_matrix[1] = {key[39-1:39], key[35-1:35], key[30-1:30]};
    key_matrix[2] = {key[34-1:34], key[29-1:29], key[24-1:24]};
end

// Plaintext to vector conversion
always @(posedge clk) begin
    if (reset) begin
        state <= 0;
        ciphertext <= 0;
        done <= 0;
    end else if (start) begin
        plaintext_vector[0] = {plaintext[14-1:8], plaintext[9-1:4], plaintext[4-1:0]};
        if (state == 0) begin
            ciphertext <= ciphertext_vector;
            state <= 1;
        end
    end
end

// Matrix multiplication with modular arithmetic
always @(posedge clk) begin
    if (state == 1) begin
        for (int i = 0; i < BLOCK_SIZE; i++) begin
            ciphertext_vector[i] = (key_matrix[0][i] * plaintext_vector[0] +
                                   key_matrix[1][i] * plaintext_vector[1] +
                                   key_matrix[2][i] * plaintext_vector[2]) mod 26;
        end
        state <= 2;
    end
end

// Convert ciphertext vector to block and map to letters
always @(posedge clk) begin
    if (state == 2) begin
        ciphertext = ciphertext_vector;
        done <= 1;
    end
end

endmodule

