                dmem_req_o <= 0;
            end
        end else if (dmem_req_o) begin
            if (ex_if_we_i) begin
                // Store transaction
                dmem_req_wdata_o <= ex_if_wdata_i;
            end
        end
    end

    // Memory response
    always @(posedge clk) begin
        if (rst_n) begin
            if (dmem_gnt_i) begin
                ex_if_ready_o <= 1;
            end else begin
                ex_if_ready_o <= 0;
            end
        end
    end

    // Writeback response
    always @(posedge clk) begin
        if (rst_n) begin
            wb_if_rvalid_o <= 0;
            wb_if_rdata_o <= 0;
        end else if (dmem_rvalid_i) begin
            wb_if_rvalid_o <= dmem_rvalid_i;
            wb_if_rdata_o <= dmem_rsp_rdata_i;
        end
    end

