module mux_synch (

	input [7:0] data_in,   				//asynchronous data input
	input req,                  		//indicating that data is available at the data_in input
	input dst_clk,                 		//destination clock
	input src_clk,                 		//source clock
	input nrst,                    		//asynchronous reset
	output reg [7:0] data_out 
);

reg [7:0] synced_data;
reg enable_sync;

// Synchronize req signal
always @(posedge src_clk) begin
    if (!nrst) begin
        enable_sync <= 0;
    end else begin
        enable_sync <= req;
    end
end

// Synchronize data_in to data_out
always @(posedge dst_clk) begin
    if (!nrst) begin
        data_out <= 8'b0000_0000;
    end else begin
        if (enable_sync) begin
            synced_data <= data_in;
            data_out <= synced_data;
        end
    end
end

// Reset all flip-flops
always @(negedge rst) begin
    data_out <= 8'b0000_0000;
end

endmodule

output.rtl/nbit_swizzling.sv:
module nbit_swizzling #(parameter DATA_WIDTH = 64) (
    input [DATA_WIDTH-1:0] data_in,
    input [1:0] sel,
    output reg [DATA_WIDTH-1:0] data_out
);

    always_comb begin
        case (sel)
            0: data_out = {DATA_WIDTH{data_in[DATA_WIDTH-1:0]}};
            1: begin
                int half_width = DATA_WIDTH / 2;
                data_out = {{(1'b1 << (half_width-1)) | {data_in[DATA_WIDTH-half_width]}}:1'b0,
                            {{(1'b0 << (half_width-1)) | {data_in[0]}}:{(half_width{data_in[half_width-1]})}}};
            end
            2: begin
                int quarter_width = DATA_WIDTH / 4;
                data_out = {{(1'b1 << (quarter_width-1)) | {data_in[DATA_WIDTH-quarter_width]}}:1'b0,
                            {{(1'b0 << (quarter_width-1)) | {data_in[2*quarter_width-2]}}:{(quarter_width{data_in[quarter_width-1]})}}:
                            {{(1'b1 << (quarter_width-1)) | {data_in[2*quarter_width-1]}}:{(quarter_width{data_in[quarter_width-1]})}}};
            end
            3: begin
                int eighth_width = DATA_WIDTH / 8;
                data_out = {{(1'b1 << (eighth_width-1)) | {data_in[DATA_WIDTH-eighth_width]}}:1'b0,
                            {{(1'b0 << (eighth_width-1)) | {data_in[2*eighth_width-2]}}:{(eighth_width{data_in[eighth_width-1]})}}:
                            {{(1'b1 << (eighth_width-1)) | {data_in[2*eighth_width-1]}}:{(eighth_width{data_in[eighth_width-1]})}}:
                            {{(1'b1 << (eighth_width-1)) | {data_in[3*eighth_width-2]}}:{(eighth_width{data_in[eighth_width-1]})}}};
            end
            default: data_out = data_in;
        endcase
    end

endmodule

input.rtl/nbit_swizzling.sv:
module nbit_swizzling #(parameter DATA_WIDTH = 64)(
    input [DATA_WIDTH-1:0] data_in,                                         // Input data of size DATA_WIDTH 
    input [1:0] sel,                	                                    //  2-bit selection signal 
    output reg [DATA_WIDTH-1:0] data_out                                    // Output data of size DATA_WIDTH 
);

integer i; 

always @(*) begin
    case(sel)
        2'b00: begin
            for (i = 0; i < DATA_WIDTH; i = i + 1) begin
                data_out[i] = data_in[DATA_WIDTH-1-i];                      
            end
        end

        2'b01: begin
            for (i = 0; i < DATA_WIDTH/2; i = i + 1) begin
                data_out[i]                = data_in[DATA_WIDTH/2-1-i];     
                data_out[DATA_WIDTH/2 + i] = data_in[DATA_WIDTH-1-i];       
            end
        end

        2'b10: begin
            for (i = 0; i < DATA_WIDTH/4; i = i + 1) begin
                data_out[i] = data_in[DATA_WIDTH/4-1-i]; 		            
                data_out[DATA_WIDTH/4 + i]   = data_in[DATA_WIDTH/2-1-i];   
                data_out[DATA_WIDTH/2 + i]   = data_in[3*DATA_WIDTH/4-1-i]; 
                data_out[3*DATA_WIDTH/4 + i] = data_in[DATA_WIDTH-1-i];     
            end
        end

        2'b11: begin
            for (i = 0; i < DATA_WIDTH/8; i = i + 1) begin
                data_out[i]                  = data_in[DATA_WIDTH/8-1-i];   
                data_out[DATA_WIDTH/8 + i]   = data_in[DATA_WIDTH/4-1-i];   
                data_out[DATA_WIDTH/4 + i]   = data_in[3*DATA_WIDTH/8-1-i]; 
                data_out[3*DATA_WIDTH/8 + i] = data_in[DATA_WIDTH/2-1-i];   
                data_out[DATA_WIDTH/2 + i]   = data_in[5*DATA_WIDTH/8-1-i]; 
                data_out[5*DATA_WIDTH/8 + i] = data_in[3*DATA_WIDTH/4-1-i]; 
                data_out[3*DATA_WIDTH/4 + i] = data_in[7*DATA_WIDTH/8-1-i]; 
                data_out[7*DATA_WIDTH/8 + i] = data_in[DATA_WIDTH-1-i];     
            end
        end
        default: begin
            data_out = data_in;						                        
        end
    endcase
end

endmodule

