module perfect_squares_generator(
    input clk,
    input reset,
    output reg [31:0] sqr_o
);

    reg [31:0] base_num = 1;

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            base_num <= 1;
            sqr_o <= 1;
        end else begin
            base_num <= base_num + 1;
            sqr_o <= base_num * base_num;
        end
    end

    always @(sqr_o) begin
        if (sqr_o > 32'hFFFFFFFF) begin
            sqr_o <= 32'hFFFFFFFF;
        end
    end

endmodule

output.rtl/pipeline_mac.sv:
module pipeline_mac #(
    parameter DWIDTH = 16,  // Bit width for multiplicand and multiplier
    parameter N      = 4    // Number of data points to accumulate over
) (
    clk,
    rstn,
    multiplicand,
    multiplier,
    valid_i,
    result,
    valid_out
);

  // Local parameter definition
  localparam DWIDTH_ACCUMULATOR = DWIDTH * N;  // Calculate accumulator bit width to avoid overflow

  // Interface Definitions
  input logic clk;                                // Clock signal
  input logic rstn;                               // Active low reset signal
  input logic [DWIDTH-1:0] multiplicand;          // Input multiplicand
  input logic [DWIDTH-1:0] multiplier;            // Input multiplier
  input logic valid_i;                            // Input valid signal
  output logic [DWIDTH_ACCUMULATOR-1:0] result;   // Accumulated result output
  output logic valid_out;                         // Output valid signal, indicates when result is ready

  // Internal signals
  logic [DWIDTH_ACCUMULATOR-1:0] mult_result_reg;    // Register to store intermediate multiplication result
  logic [DWIDTH_ACCUMULATOR-1:0] accumulation_reg;   // Register to store accumulated result
  logic [$clog2(N):0] counter;                       // Counter to track the number of accumulations
  logic [$clog2(N):0] counter_reg;                   // Register to hold the value of the counter
  logic count_rst, accumulator_rst;                  // Reset signals for counter and accumulator
  logic valid_out_s0,valid_out_s1,valid_out_s2;      // Intermediate Signals indicating that the valid output is ready
  logic valid_i_s1;                                  // Intermediate Signals indicating input valid signal

  // Procedural blocks

  // Stage 1 of the pipeline: Perform multiplication
  always @(posedge clk or negedge rstn) begin
    if (!rstn) begin
      mult_result_reg <= 0;
      accumulation_reg <= 0;
      counter_reg <= 0;
      count_rst <= 1;
      valid_out_s1 <= 0;
      valid_out_s2 <= 0;
      accumulator_rst <= 1;
    end else if (valid_i) begin
      mult_result_reg <= ((multiplicand * multiplier) >> (DWIDTH - 1));
      counter_reg <= counter + 1;
    end
  end

  // Stage 2 of the pipeline: Accumulation logic
  always @(posedge clk or negedge rstn) begin
    if (!rstn) begin
      accumulation_reg <= 0;
      valid_out_s1 <= 0;
      valid_out_s2 <= 0;
    end else if (valid_i) begin
      accumulation_reg <= (accumulation_reg + mult_result_reg) >> 1;
      if (counter == N-1) begin
        valid_out_s0 <= 1;
        valid_out_s1 <= 0;
        valid_out_s2 <= 1;
      end
    end
  end

  // N-bit counter to track the number of accumulations
  always @(posedge clk or negedge rstn) begin
    if (!rstn) begin
      counter_reg <= 0;
    end else begin
      if (valid_i) begin
        counter_reg <= (counter_reg + 1) & (N-1);
      end
    end
  end

  // Register valid output for 2-stage pipeline
  always @(posedge clk or negedge rstn) begin
    if (!rstn) begin
      valid_out <= 0;
    end else begin
      valid_out <= valid_out_s1 & ~valid_out_s2;
    end
  end

  // Combinational Assignments
  assign counter = count_rst ? 'b1 : (valid_i & rstn ? (counter_reg + 'd1) : counter_reg);  // Increment counter on valid input
  assign valid_out_s0 = (counter_reg == N-1);    // Assert valid_out_s0 when N accumulations are done
  assign count_rst = valid_out_s1;                  // Reset counter after N accumulations
  assign accumulator_rst = valid_out_s1;            // Reset accumulator after N accumulations
  assign result = accumulation_reg;              // Output final result assignment
  assign valid_out = valid_out_s1 & ~valid_out_s2; // Valid_out signal generation by detecting posedge of previous stages of valid out

endmodule : pipeline_mac

output.rtl/piso_8bit.sv:
library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

entity piso_8bit is
    Port (
        clk : in std_logic;
        rst : in std_logic;
        serial_out : out std_logic
    );
end piso_8bit;

architecture Behavioral of piso_8bit is
    signal tmp : std_logic_vector(7 downto 0) := "00000001";
begin
    process(clk, rst)
    begin
        if rst = '0' then
            tmp <= "00000000";
        elsif rising_edge(clk) then
            if tmp("7") = '1' then
                tmp <= tmp("6 downto 0") & "0";
            else
                tmp <= tmp + 1;
            end if;
            serial_out <= tmp("0");
        end if;
    end process;
end Behavioral;

output.rtl/pkt_detector.sv:
// State Register
always_ff @(posedge clk or negedge reset) begin
    if (!reset)
        curr_state <= S_IDLE;
    else
        curr_state <= nxt_state;
end

// Next State Logic
always_comb begin
    case (curr_state)
        S_IDLE: 
            if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                nxt_state = S_ACTIVE;
            else
                nxt_state = S_IDLE;

        S_ACTIVE: 
            if (byte_cnt == PKT_BYTES)
                nxt_state = S_WAIT_END;
            else
                nxt_state = S_ACTIVE;

        S_WAIT_END: 
            if (pkt_reg[159:152] == END_SYMBOL)
                nxt_state = S_IDLE;
            else
                nxt_state = S_ERROR;

        S_ERROR: 
            if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                nxt_state = S_ACTIVE;
            else
                nxt_state = S_ERROR;

        default: nxt_state = S_IDLE;
    endcase
end

// State Logic
always_comb begin
    case (curr_state)
        S_ACTIVE: 
            begin
                byte_cnt <= byte_cnt + 1;
                pkt_reg <= {pkt_reg[8:0], data_in};
            end
        S_WAIT_END: 
            begin
                // Update packet data
                pkt_data <= pkt_reg;

                // Update packet count
                pkt_count <= pkt_count + 1;

                // Detect operations based on packet header
                mem_read_detected <= (pkt_reg[31:24] == 4'h00);
                mem_write_detected <= (pkt_reg[31:24] == 4'h01);
                io_read_detected <= (pkt_reg[31:24] == 4'h10);
                io_write_detected <= (pkt_reg[31:24] == 4'h11);
                cfg_read0_detected <= (pkt_reg[31] == 4'h00);
                cfg_write0_detected <= (pkt_reg[31] == 4'h01);
                cfg_read1_detected <= (pkt_reg[30] == 4'h00);
                cfg_write1_detected <= (pkt_reg[30] == 4'h01);
                completion_detected <= 1'b1;
                completion_data_detected <= pkt_data;
            end
        S_ERROR: 
            begin
                error_detected <= 1'b1;
                byte_cnt <= 0;
                pkt_reg <= 160'h0;
            end
        default: begin
            byte_cnt <= 0;
            pkt_reg <= 160'h0;
        end
    endcase
end

