module prim_max_find #(
  parameter int NumSrc = 8,
  parameter int Width = 8,
  // Corrected Derived parameters
  localparam int NumLevels = $clog2(NumSrc); // Removed the '-1'
  localparam int NumNodes = 2**NumLevels; // Corrected calculation
) (
