    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            rem <= 8'd0;
        else if (start && !busy)
            rem <= 8'd0;
        else if (busy)
            rem <= next_rem[7:0];
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            remainder <= 8'd0;
        else if (start && !busy && divisor == 8'd0)
            remainder <= 8'hFF;
        else if (busy && bit_counter == 4'd0) begin
            if (next_rem[7:0] != 8'd0)
                remainder <= next_rem[7:0] + 1'b1;
            else
                remainder <= next_rem[7:0];
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            bit_counter <= 4'd0;
        else if (start && !busy) begin
            if (divisor != 8'd0)
                bit_counter <= 4'd7;  // Start from MSB
        end
        else if (busy && bit_counter != 4'd0) begin
            bit_counter <= bit_counter - 4'd1; // Normal decrement
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            divisor_reg <= 8'd0;
        else if (start && !busy && divisor != 8'd0)
            divisor_reg <= divisor;
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            done <= 1'b0;
        else if (start && !busy) begin
            if (divisor == 8'd0)
                done <= 1'b1;
            else
                done <= 1'b0;
        end
        else if (busy && bit_counter == 4'd0)
            done <= 1'b1;
        else
            done <= 1'b0;
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            busy <= 1'b0;
        else if (start && !busy) begin
            if (divisor != 8'd0)
                busy <= 1'b1;
            else
                busy <= 1'b0;
        end
        else if (busy && bit_counter == 4'd0)
            busy <= 1'b0;
    end

endmodule

