module reed_solomon_encoder #(
    parameter DATA_WIDTH = 8,   // Width of input data symbols
    parameter N = 255,         // Total number of symbols in the codeword
    parameter K = 223          // Number of data symbols
) (
    input wire clk,
    input wire reset,
    input wire enable,
    input wire [DATA_WIDTH-1:0] data_in,
    input wire valid_in,
    output reg [DATA_WIDTH-1:0] codeword_out,
    output reg valid_out,
    output reg [DATA_WIDTH-1:0] parity_0,
    output reg [DATA_WIDTH-1:0] parity_1
);

    localparam PARITY_SYMBOLS = N - K;// Number of parity symbols 

    // Internal registers for shift-register based encoding
    reg [DATA_WIDTH-1:0] feedback;
    reg [DATA_WIDTH-1:0] parity_register [PARITY_SYMBOLS-1:0];

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            // Reset all registers
            parity_0 <= 0 ;
            parity_1 <= 0 ;
            codeword_out <= 0;
            valid_out <= 0;
            feedback <= 0;
        end else if (enable && valid_in) begin
            // Compute parity_0 and parity_1 using generator_polynomial
            generator_polynomial = generator_polynomial();
            parity_0 <= feedback ^ parity_register[0];
            parity_1 <= feedback ^ parity_register[PARITY_SYMBOLS-1];
            feedback <= parity_0 ^ parity_1;
            codeword_out <= data_in << PARITY_SYMBOLS | parity_0 << 0 | parity_1 << (DATA_WIDTH-1);
            valid_out <= (data_in != 0) && (parity_0 != 0) && (parity_1 != 0);
        end
    end

    function [DATA_WIDTH-1:0] generator_polynomial;
        // Choose between 8'h1D (degree 1) and 8'h33 (degree 32) based on some condition
        // Here we assume a simple condition based on the index for demonstration purposes
        // Replace this with the actual condition for your application
        if (index < 128) begin
            return 8'h1D;
        end else begin
            return 8'h33;
        end
    endfunction

endmodule

input.rtl/cvdp_copilot_register_file_2R1W.sv:
module cvdp_copilot_register_file_2R1W #(
    parameter DATA_WIDTH = 32  // Configurable data width
) (
    // Inputs
    input  logic [DATA_WIDTH-1:0] din,    // Input data
    input  logic [4:0] wad1,              // Write address
    input  logic [4:0] rad1,              // Read address 1
    input  logic [4:0] rad2,              // Read address 2
    input  logic wen1,                    // Write-enable signal
    input  logic ren1,                    // Read-enable signal 1
    input  logic ren2,                    // Read-enable signal 2
    input  logic clk,                     // Clock signal
    input  logic resetn,                  // Active-low reset

    // Outputs
    output logic [DATA_WIDTH-1:0] dout1,   // Output data 1
    output logic [DATA_WIDTH-1:0] dout2,   // Output data 2
    output logic collision                 // Collision flag
);

    // -------------------------------
    // Internal Registers and Wires
    // -------------------------------

    // Register file memory with 32 entries of DATA_WIDTH-bit words
    logic [DATA_WIDTH-1:0] rf_mem [0:31];
    logic [31:0] rf_valid;                   // Validity of each register entry
    integer i;

    // Clock Gating Enable Signal: High when any read or write operation is active
    wire clk_en = wen1 | ren1 | ren2;

    // Clock Gating Logic (Integrated from cgate module)
    logic gated_clk;    // Gated clock output
    logic en_latch;     // Enable latch

    // Latch to hold the enable signal when clk is low
    always @ (clk or clk_en) begin
        if (!clk)
            en_latch <= clk_en;
    end

    // Gated clock generation
    assign gated_clk = clk && en_latch;

    // -------------------------------
    // Register File Operations
    // -------------------------------

    // Reset and Write Operation Logic with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            // Initialize all memory locations to zero
            for (i = 0; i < 32; i = i + 1) begin
                rf_mem[i] <= {DATA_WIDTH{1'b0}};
            end
            rf_valid <= 0;  // Mark all entries as invalid
        end 
        else if (wen1) begin
            rf_mem[wad1]    <= din;  // Write operation
            rf_valid[wad1]  <= 1;    // Mark written address as valid
        end
    end

    // Read Data Output Logic for Port 1 with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            dout1 <= 0;
        end 
        else if (ren1) begin
            dout1 <= rf_valid[rad1] ? rf_mem[rad1] : 0;
        end 
        else begin
            dout1 <= 0;
        end
    end

    // Read Data Output Logic for Port 2 with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            dout2 <= 0;
        end 
        else if (ren2) begin
            dout2 <= rf_valid[rad2] ? rf_mem[rad2] : 0;
        end 
        else begin
            dout2 <= 0;
        end
    end

    // -------------------------------
    // Collision Detection Logic
    // -------------------------------

    // Collision Flag Logic with Original Clock (non-gated)
    always_ff @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            collision <= 0;
        end 
        else begin
            collision <= (
                (ren1 && ren2 && (rad1 == rad2)) ||          // Both reads to the same address
                (wen1 && ren1 && (wad1 == rad1)) ||          // Write and read to the same address
                (wen1 && ren2 && (wad1 == rad2))             // Write and read to the same address
            );
        end
    end

endmodule

output.rtl/cvdp_copilot_register_file_2R1W.sv:
module cvdp_copilot_register_file_2R1W #(
    parameter DATA_WIDTH = 32,
    parameter DEPTH = 32
) (
    input logic test_mode,
    input logic clk,
    input logic resetn,
    input logic din,
    input logic [DATA_WIDTH-1:0] wad1,
    input logic wen1,
    input logic rad1,
    input logic ren1,
    input logic ren2,
    output logic bist_done,
    output logic bist_fail
);

    // Existing declarations...

    // BIST Control and Status Signals
    logic bist_state = 0;
    logic bist_addr;
    logic bist_pattern;
    logic bist_compare_pass;

    // BIST Phases
    logic write_phase;
    logic read_phase;

    // BIST Sequence Logic
    always_comb begin
        if (test_mode) begin
            if (bist_state == 0) begin
                bist_state = 1;
                write_phase = 1;
                bist_addr = 0;
                bist_pattern = {DATA_WIDTH{1'b0}};
            end else if (bist_state == 1) begin
                bist_state = 2;
                write_phase = 1;
                bist_addr = bist_addr + 1;
                bist_pattern = {DATA_WIDTH{1'b0}};
            end else if (bist_state == 2) begin
                bist_state = 3;
                read_phase = 1;
                bist_addr = bist_addr + 1;
            end
        end
    end

    always_comb begin
        if (bist_state == 3) begin
            bist_state = 4;
            read_phase = 1;
            bist_addr = bist_addr + 1;
            bist_compare_pass = (dout1 == bist_pattern[bist_addr]) && (dout2 == bist_pattern[bist_addr]);
        end
        if (bist_state == 4) begin
            bist_state = 5;
            bist_done = 1;
            bist_fail = ~bist_compare_pass;
        end
    end

    // Existing Register File Operations...

    // Updated Collision Detection Logic to include BIST status
    always_comb begin
        if (!resetn) begin
            collision <= 0;
        end
        else begin
            collision <= (
                (ren1 && ren2 && (rad1 == rad2)) ||
                (wen1 && ren1 && (wad1 == rad1)) ||
                (wen1 && ren2 && (wad1 == rad2)) ||
                (bist_fail)
            );
        end
    end

endmodule

module cvdp_copilot_register_file_2R1W #(
    parameter DATA_WIDTH = 32  // Configurable data width
) (
    // Inputs
    input  logic [DATA_WIDTH-1:0] din,    // Input data
    input  logic [4:0] wad1,              // Write address
    input  logic [4:0] rad1,              // Read address 1
    input  logic [4:0] rad2,              // Read address 2
    input  logic wen1,                    // Write-enable signal
    input  logic ren1,                    // Read-enable signal 1
    input  logic ren2,                    // Read-enable signal 2
    input  logic clk,                     // Clock signal
    input  logic resetn,                  // Active-low reset

    // Outputs
    output logic [DATA_WIDTH-1:0] dout1,   // Output data 1
    output logic [DATA_WIDTH-1:0] dout2,   // Output data 2
    output logic collision               // Collision flag
);

    // Internal Registers and Wires
    logic [DATA_WIDTH-1:0] rf_mem [0:31];   // Register file memory
    logic [DATA_WIDTH-1:0] rf_dout1, rf_dout2;  // Output data for read ports
    logic [31:0] rf_valid;                   // Validity of each register entry
    integer i;

    logic clk_en, en_latch;                   // Enable latch and clock enable signal

    // Enable latch generation logic
    always_ff @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            en_latch <= 0;
        end else begin
            en_latch <= wen1 | ren1 | ren2;
        end
    end

    // Gated clock output logic
    logic gated_clk;
    always_ff @(posedge en_latch or negedge resetn) begin
        if (!resetn) begin
            gated_clk <= 0;
        end else if (en_latch) begin
            gated_clk <= clk;
        end
    end

    // Reset and Write Operation Logic with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            rf_valid <= 0;  // Mark all entries as invalid
            rf_dout1 <= 0;
            rf_dout2 <= 0;
        end else if (wen1) begin
            // Write operation logic (assuming a single write operation for simplicity)
            rf_mem[wad1] <= din;
            rf_valid[wad1] <= 1;
        end
    end

    // Read Data Output Logic for Port 1 with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            dout1 <= 0;
        end else if (ren1) begin
            // Read operation logic for port 1
            dout1 <= rf_valid[rad1] ? rf_dout1[rad1] : 0;
        end else begin
            dout1 <= 0;
        end
    end

    // Read Data Output Logic for Port 2 with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            dout2 <= 0;
        end else if (ren2) begin
            // Read operation logic for port 2
            dout2 <= rf_valid[rad2] ? rf_dout2[rad2] : 0;
        end else begin
            dout2 <= 0;
        end
    end

    // Collision Detection Logic
    logic collision;
    always_ff @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            collision <= 0;
        end else begin
            // Collision detection logic
            collision = (rad1 == rad2) | (wen1 == rad1) | (wen1 == rad2);
        end
    end

endmodule

output.rtl/restore_division.sv:
module restoring_division #(parameter WIDTH = 6) (
    input wire clk,
    input wire rst_n,
    input wire start,
    input wire [WIDTH-1:0] dividend,
    input wire [WIDTH-1:0] divisor,
    output reg [WIDTH-1:0] quotient,
    output reg [WIDTH-1:0] remainder,
    output reg valid
);

    // Internal registers
    reg [WIDTH-1:0] int_dividend;
    reg [WIDTH-1:0] int_divisor;
    reg [WIDTH-1:0] int_remainder;
    reg [WIDTH-1:0] int_quotient;

    // Internal signals
    reg [WIDTH-1:0] shift_reg;

    // Processor
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            int_dividend <= 0;
            int_divisor <= 0;
            int_remainder <= 0;
            int_quotient <= 0;
            valid <= 0;
        end else if (start) begin
            int_dividend <= dividend;
            int_divisor <= divisor;
            valid <= 1;
        end else if (valid) begin
            if (WIDTH == 1'b1 || WIDTH == 2'b10) begin
                if (int_remainder[WIDTH-1] == 0) begin
                    shift_reg <= int_remainder << 1;
                    shift_reg(WIDTH-1) <= int_dividend[WIDTH-1];
                    int_quotient(WIDTH-1) <= 1'b1;
                    int_remainder <= shift_reg;
                end else begin
                    shift_reg <= int_remainder << 1;
                    int_remainder <= shift_reg;
                    int_quotient(WIDTH-1) <= 1'b0;
                end
            end else begin
                shift_reg <= int_remainder << 1;
                shift_reg(WIDTH-1) <= int_dividend[WIDTH-1];
                if (int_remainder < int_divisor) begin
                    int_quotient(WIDTH-1) <= 1'b0;
                    int_remainder <= int_remainder << 1;
                end else begin
                    int_quotient(WIDTH-1) <= 1'b1;
                    int_remainder <= int_remainder - int_divisor;
                end
            end
        end
    end

    // Outputs
    assign quotient = int_quotient;
    assign remainder = int_remainder;

endmodule

