            out_data_aux[1][(i+1)*CHUNK-1-:CHUNK] = out_data_intra_block_reg[i%4][(((i+1)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
            out_data_aux[2][(i+1)*CHUNK-1-:CHUNK] = out_data_intra_block_reg[i%4][(((i+2)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
            out_data_aux[3][(i+1)*CHUNK-1-:CHUNK] = out_data_intra_block_reg[i%4][(((i+3)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
         end
         counter_sub_out <= counter_sub_out + 1;
         out_data        <= out_data_aux[counter_sub_out];
      end
   end
end

endmodule

input.rtl/intra_block.sv:
module intra_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter DATA_WIDTH = ROW_COL_WIDTH*ROW_COL_WIDTH
)(
    input logic [DATA_WIDTH-1:0] in_data,  // Input: 256 bits
    output logic [DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

    // Temporary storage for intermediate calculations
    logic [3:0] r_prime [0:255]; // Row index for each bit
    logic [3:0] c_prime [0:255]; // Column index for each bit

    logic [ROW_COL_WIDTH-1:0] prev_out_data [ROW_COL_WIDTH-1:0];

    always_comb begin
       for(int i = 0; i < 256; i++) begin
         if (i < 128) begin
            r_prime[i] = (i - 2 * (i / 16)) % 16;
            c_prime[i] = (i -     (i / 16)) % 16;
         end
         else begin
            r_prime[i] = (i - 2 * (i / 16) - 1) % 16;
            c_prime[i] = (i - (i / 16) - 1) % 16;
         end
       end
    end
    int j, k;
    logic [7:0] output_index[256];
    always_comb begin
      for (j = 0; j < 256; j++) begin
           output_index[j] = r_prime[j] * 16 + c_prime[j];
           out_data[j]     = in_data[output_index[j]];
        end
    end
endmodule

output.rtl/intra_block.sv:
module intra_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter DATA_WIDTH = ROW_COL_WIDTH*ROW_COL_WIDTH
)(
    input logic [DATA_WIDTH-1:0] in_data,  // Input: 256 bits
    output logic [DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

    // Reduced temporary storage by using a single lookup table
    logic [3:0] index_table [0:255];

    always_comb begin
        // Generate the index table for both row and column
        integer i;
        for (i = 0; i < 256; i++) begin
            if (i < 128) begin
                index_table[i] = (i - 2 * (i / 16)) % 16;
            end
            else begin
                index_table[i] = (i - 2 * (i / 16) - 1) % 16;
            end
        end

        // Perform the transformation using the index table
        integer j;
        for (j = 0; j < 256; j++) begin
            out_data[j] = in_data[index_table[j]];
        end
    end
endmodule

output.rtl/sdram_controller.sv:
module sdram_controller (
    input clk,
    input reset,
    input [23:0] addr,
    input [15:0] data_in,
    output reg [15:0] data_out,
    output reg sdram_clk,
    output reg sdram_cke,
    output reg sdram_cs,
    output reg sdram_ras,
    output reg sdram_cas,
    output reg sdram_we,
    input [7:0] sdram_addr,
    input [3:0] sdram_ba,
    output [15:0] sdram_dq,
    output [15:0] dq_out
);

    // State declaration
    reg [2:0] state;
    reg [3:0] row_addr;
    reg [3:0] col_addr;

    // Initialization sequence
    initial begin
        state = 0; // INIT
    end

    // State transition logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= 0;
            row_addr <= 0;
            col_addr <= 0;
        end else if (state == 0) begin
            // 10-cycle initialization
            for (int i = 0; i < 10; i = i + 1) begin
                state <= state + 1;
                #10;
            end
            state <= 1; // IDLE
        end else if (state == 1) begin
            // Monitor for read/write request
            if (read || write) begin
                state <= 2; // ACTIVATE
            end
        end else if (state == 2) begin
            // Assert CS, RAS, CAS, and appropriate WE
            if (read) begin
                sdram_cs <= 1;
                sdram_ras <= 1;
                sdram_cas <= col_addr;
                sdram_we <= 0;
                state <= 3; // READ
            end else if (write) begin
                sdram_cs <= 1;
                sdram_ras <= 1;
                sdram_cas <= col_addr;
                sdram_we <= 1;
                state <= 4; // WRITE
            end
        end else if (state == 3 || state == 4) begin
            // Perform read/write operation
            // Assuming the operation is completed and moving back to IDLE
            state <= 1;
        end
    end

    // FSM logic for ACTIVATE, READ, and WRITE
    always @(state, addr, data_in, read, write) begin
        case (state)
            2: begin // ACTIVATE
                if (addr == row_addr) begin
                    sdram_ras <= 1;
                    state <= (read ? 3 : 4);
                end else begin
                    row_addr <= addr;
                end
            end
            3: begin // READ
                sdram_dq <= data_in;
                sdram_dq_out <= data_dq;
                state <= 1;
            end
            4: begin // WRITE
                sdram_dq <= data_out;
                state <= 1;
            end
            default: begin
                // Auto-refresh logic
                if (col_addr == 0 && state == 1 && (clk_counter % 1024 == 0)) begin
                    state <= 5; // REFRESH
                    col_addr <= 0;
                    sdram_we <= 0;
                end
            end
        endcase
    end

    // Clock counter
    reg [15:0] clk_counter = 0;
    always @(posedge clk) begin
        clk_counter <= clk_counter + 1;
    end

    // Auto-refresh command
    always @(state) begin
        case (state)
            5: begin // REFRESH
                sdram_cs <= 1;
                sdram_ras <= 1;
                sdram_cas <= col_addr;
                sdram_we <= 0;
                state <= 1;
            end
        endcase
    end

endmodule

output.rtl/alu_seq.v:
module alu_seq (
    input i_clk,          // Clock signal
    input i_rst_b,        // Active-low asynchronous reset
    input [3:0] i_operand_a, // 4-bit input operand A
    input [3:0] i_operand_b, // 4-bit input operand B
    input [2:0] i_opcode,    // 3-bit operation code
    input [7:0] i_key_in,    // 8-bit security key input
    output reg [7:0] o_result // 8-bit operation result
);

    // Internal configuration
    reg [7:0] p_key = 8'hAA;

    // State register
    reg [7:0] s_result = 8'h0000;

    // Reset logic
    always @(posedge i_clk or negedge i_rst_b) begin
        if (!i_rst_b) begin
            s_result <= 8'h0000;
        end else begin
            if (i_key_in == p_key) begin
                case(i_opcode)
                    3'b000: s_result <= i_operand_a + i_operand_b;
                    3'b001: s_result <= i_operand_a - i_operand_b;
                    3'b010: s_result <= i_operand_a * i_operand_b;
                    3'b011: s_result <= i_operand_a & i_operand_b;
                    3'b100: s_result <= i_operand_a | i_operand_b;
                    3'b101: s_result <= ~i_operand_a;
                    3'b110: s_result <= i_operand_a ^ i_operand_b;
                    3'b111: s_result <= ~(i_operand_a ^ i_operand_b);
                    default: s_result <= 8'h0000;
                endcase
            end
        end
    end

    // Output logic
    assign o_result = s_result;

endmodule

output.rtl/secure_read_write_bus_interface.v:
module secure_read_write_bus_interface #(
    parameter p_data_width = 8,
    parameter p_addr_width = 8,
    parameter p_configurable_key = 8'hAA
)(
    input wire i_addr,
    input wire i_data_in,
    input wire i_key_in,
    input wire i_read_write_enable,
    input wire i_capture_pulse,
    input wire i_reset_bar,
    output reg o_data_out,
    output reg o_error
);

    // Internal registers
    reg [p_data_width-1:0] data_reg;
    reg [p_addr_width-1:0] address_reg;
    reg internal_key = p_configurable_key;

    // Reset condition
    always @(posedge i_capture_pulse or posedge i_reset_bar) begin
        if (i_reset_bar) begin
            o_data_out <= 0;
            o_error <= 1;
            data_reg <= 0;
            address_reg <= 0;
        end else if (i_capture_pulse) begin
            address_reg <= i_addr;
            data_reg <= i_data_in;
        end
    end

    // Read operation
    always @(posedge i_capture_pulse) begin
        if (i_read_write_enable) begin
            if (i_key_in == internal_key) begin
                o_data_out <= data_reg;
                o_error <= 0;
            end else begin
                o_data_out <= 0;
                o_error <= 1;
            end
        end
    end

    // Write operation
    always @(posedge i_capture_pulse) begin
        if (!i_read_write_enable) begin
            if (i_key_in == internal_key) begin
                data_reg <= i_data_in;
                o_error <= 0;
            end else begin
                o_error <= 1;
                o_data_out <= 0;
            end
        end
    end

endmodule

output.rtl/secure_read_write_register_bank.v:
module secure_read_write_register_bank #(
    parameter p_addr_width = 8,
    parameter p_data_width = 8,
    parameter p_unlock_code_0 = 0xAB,
    parameter p_unlock_code_1 = 0xCD
) (
    input [p_addr_width-1:0] i_addr,
    input [p_data_width-1:0] i_data_in,
    input i_read_write_enable,
    input i_capture_pulse,
    input i_rst_n,
    output reg [p_data_width-1:0] o_data_out
);

    // Unlock control
    reg [p_data_width-1:0] unlock_status;
    reg [p_addr_width-1:0] address_register [0:2];

    // Unlock sequence
    always @(posedge i_capture_pulse) begin
        if (!i_rst_n) begin
            unlock_status <= 0;
            address_register[0] <= 0;
            address_register[1] <= 0;
        end else if (i_read_write_enable == 0) begin
            if (address_register[0] != p_unlock_code_0) begin
                unlock_status <= 0;
                address_register[0] <= 0;
            end else if (address_register[1] != p_unlock_code_1) begin
                unlock_status <= 0;
                address_register[1] <= 0;
            end else begin
                unlock_status <= 1;
                address_register[2] <= i_data_in;
            end
        end else begin
            unlock_status <= unlock_status;
        end
    end

    // Read operation
    always @(posedge i_capture_pulse) begin
        if (i_read_write_enable == 1 && unlock_status) begin
            o_data_out <= address_register[i_addr];
        end else if (i_read_write_enable == 1 && !unlock_status) begin
            o_data_out <= 0;
        end
    end

    // Write operation
    always @(posedge i_capture_pulse) begin
        if (i_read_write_enable == 0 && unlock_status) begin
            if (i_addr == 0 || i_addr == 1) begin
                address_register[i_addr] <= i_data_in;
            end else begin
                o_data_out <= 0;
            end
        end else if (i_read_write_enable == 0 && !unlock_status) begin
            o_data_out <= 0;
        end
    end

    // Reset logic
    always @(posedge i_rst_n) begin
        unlock_status <= 0;
        address_register[0] <= 0;
        address_register[1] <= 0;
    end

endmodule

output.rtl/secure_variable_timer.v:
module secure_variable_timer (
    input wire i_clk,
    input wire i_rst_n,
    input wire i_data_in,
    output reg [3:0] o_time_left,
    output reg o_processing,
    output reg o_completed,
    input wire i_ack
);

    // Internal registers
    reg [3:0] delay;
    reg [9:0] counter;
    reg [3:0] time_left_reg;
    reg [3:0] current_delay;
    reg [3:0] next_delay;
    reg [3:0] delay_detected;

    // State declaration
    typedef enum reg (
        idle,
        configure_delay,
        counting,
        done
    ) state_t;
    state_t current_state, next_state;

    // State transition logic
    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            current_state <= idle;
            counter <= 0;
            time_left_reg <= 0;
            delay_detected <= 0;
        end else begin
            case (current_state)
                idle: begin
                    if (i_data_in === 4'b1101) begin
                        current_state <= configure_delay;
                        delay_detected <= 1;
                    end else begin
                        current_state <= idle;
                    end
                end
                configure_delay: begin
                    if (!delay_detected) begin
                        delay <= i_data_in;
                        next_delay <= delay;
                        current_state <= counting;
                    end else begin
                        current_state <= configure_delay;
                    end
                end
                counting: begin
                    if (counter >= (next_delay + 1) * 1000) begin
                        o_time_left <= time_left_reg;
                        o_processing <= 1;
                        o_completed <= 1;
                        next_state <= done;
                    end else begin
                        time_left_reg <= time_left_reg - 1;
                        counter <= counter + 1;
                        current_state <= counting;
                    end
                end
                done: begin
                    if (i_ack) begin
                        current_state <= idle;
                        time_left_reg <= 0;
                        counter <= 0;
                    end else begin
                        current_state <= done;
                    end
                end
            endcase
        end
    end

    // Counting logic
    always @(posedge i_clk) begin
        if (delay_detected) begin
            if (current_state == counting) begin
                counter <= counter + 1;
            end
        end
    end

endmodule

output.rtl/serial_in_parallel_out_8bit.sv:
module serial_in_parallel_out_8bit(
    input clock,
    input serial_in,
    output reg [7:0] parallel_out
);

    // State register
    reg [7:0] state;

    // Clock edge detection
    always @(posedge clock) begin
        if (serial_in) begin
            // Shift in the new bit
            state <= state << 1;
            // Insert the new bit at the LSB
            state[0] <= serial_in;
        end
        // Output the parallel data
        parallel_out <= state;
    end

    // Initialization
    initial begin
        state <= 8'b00000000; // Set the initial state to all x's
    end

endmodule

