output.rtl/signedadder.v:
module signedadder #(parameter DATA_WIDTH = 8)(
    input i_clk,
    input i_rst_n,
    input i_start,
    input i_enable,
    input i_mode,
    input i_clear,
    input [DATA_WIDTH-1:0] i_operand_a,
    input [DATA_WIDTH-1:0] i_operand_b,
    output reg [DATA_WIDTH-1:0] o_resultant_sum,
    output reg o_overflow,
    output reg o_ready,
    output reg [1:0] o_status
);

    // Internal signals
    reg [DATA_WIDTH-1:0] a_reg, b_reg;
    reg [1:0] state, next_state;

    // State encoding
    localparam IDLE = 2'b00, LOAD = 2'b01, COMPUTE = 2'b10, OUTPUT = 2'b11;

    // State transition logic
    always @(posedge i_clk or posedge i_rst_n) begin
        if (i_rst_n) begin
            state <= IDLE;
            a_reg <= 0;
            b_reg <= 0;
            o_overflow <= 0;
            o_resultant_sum <= 0;
            o_ready <= 0;
        end else if (i_start && i_enable) begin
            state <= IDLE;
        end else if (state == IDLE && i_start && i_enable) begin
            state <= LOAD;
        end else if (state == LOAD) begin
            a_reg <= i_operand_a;
            b_reg <= i_operand_b;
            state <= COMPUTE;
        end else if (state == COMPUTE) begin
            case (i_mode)
                2'b0: o_resultant_sum <= a_reg + b_reg;
                2'b1: o_resultant_sum <= a_reg - b_reg;
                default: o_resultant_sum <= 0;
            endcase
            // Overflow detection
            if ((i_mode == 2'b0 && (a_reg[DATA_WIDTH-1] & b_reg[DATA_WIDTH-1]) != 0) ||
                (i_mode == 2'b1 && (!(a_reg[DATA_WIDTH-1] & b_reg[DATA_WIDTH-1]))) ||
                (a_reg[DATA_WIDTH-1] == b_reg[DATA_WIDTH-1] && a_reg[DATA_WIDTH-2:0] < b_reg[DATA_WIDTH-2:0]))
                o_overflow <= 1;
            else
                o_overflow <= 0;
            state <= OUTPUT;
        end
    end

    // Output logic
    always @(state) begin
        case (state)
            IDLE: o_status <= IDLE;
            LOAD: o_status <= LOAD;
            COMPUTE: o_status <= COMPUTE;
            OUTPUT: o_status <= OUTPUT;
            default: o_status <= IDLE;
        endcase
    end

    // Outputs
    always @(state or o_resultant_sum or o_overflow) begin
        case (state)
            IDLE: o_ready <= 0;
            LOAD: o_ready <= 0;
            COMPUTE: o_ready <= 1;
            OUTPUT: o_ready <= 1;
            default: o_ready <= 0;
        endcase
    end

endmodule

output.rtl/spi_fsm.v:
module spi_fsm (
    input  wire         i_clk,       // System clock
    input  wire         i_rst_b,     // Active-low async reset
    input  wire [15:0]  i_data_in,   // Parallel 16-bit data to transmit
    input  wire         i_enable,    // Enable block
    input  wire         i_fault,     // Fault indicator
    input  wire         i_clear,     // Forces FSM to clear/idle

    output reg          o_spi_cs_b,  // SPI chip select (active-low)
    output reg          o_spi_clk,   // SPI clock
    output reg          o_spi_data,  // Serialized SPI data out
    output reg [4:0]    o_bits_left, // Bits left to transmit
    output reg          o_done,      // Single-cycle pulse when done or error
    output reg [1:0]    o_fsm_state  // FSM state for external monitoring
);

    // Internal signals
    reg [1:0] internal_state, next_state;
    reg [4:0] counter;

    // State transition logic
    always @(posedge i_clk or posedge i_rst_b) begin
        if (i_rst_b) begin
            internal_state <= 2'b00;
            o_spi_cs_b <= 1;
            o_spi_clk <= 0;
            o_spi_data <= 0;
            o_bits_left <= 10'b0;
            o_done <= 0;
            o_fsm_state <= 2'b00;
        end else begin
            case (internal_state)
                2'b00: begin
                    if (i_enable) begin
                        internal_state <= 2'b01;
                        o_spi_cs_b <= 0;
                        o_spi_clk <= 1;
                    end
                end
                2'b01: begin
                    if (o_bits_left > 0) begin
                        internal_state <= 2'b10;
                        counter <= counter + 1;
                    end else begin
                        internal_state <= 2'b11;
                        o_done <= 1;
                    end
                end
                2'b10: begin
                    if (counter > 0) begin
                        internal_state <= 2'b00;
                        o_spi_clk <= ~o_spi_clk;
                        counter <= counter - 1;
                    end else begin
                        internal_state <= 2'b01;
                    end
                end
                2'b11: begin
                    if (i_fault) begin
                        internal_state <= 2'b00;
                        o_spi_cs_b <= 1;
                        o_spi_clk <= 0;
                        o_spi_data <= 0;
                        o_done <= 0;
                        o_fsm_state <= 2'b00;
                    end
                end
            endcase
        end
    end

    // Output logic
    always @(*) begin
        o_spi_data = i_data_in[4:0];
        o_bits_left = counter;
    end

endmodule

output.rtl/unique_number_identifier.v:
module unique_number_identifier #(
    parameter p_bit_width = 8,
    parameter p_max_numbers = 16
) (
    input wire i_clk,
    input wire i_rst_n,
    input wire i_ready,
    input wire [p_bit_width-1:0] i_number,
    output reg [p_bit_width-1:0] o_unique_number
);

    // Internal state memory for storing input numbers
    reg [p_bit_width-1:0] number_storage [p_max_numbers-1:0];
    integer count;

    // State machine
    always @(posedge i_clk or posedge i_rst_n) begin
        if (i_rst_n) begin
            count <= 0;
            o_unique_number <= 0;
            number_storage <= {p_bit_width{1'b0}};
        end else begin
            case (count)
                0: begin
                    if (i_ready) begin
                        number_storage[count] <= i_number;
                        count <= 1;
                    end
                end
                1: begin
                    if (i_number == number_storage[count-1]) begin
                        count <= count;
                    end else begin
                        count <= count + 1;
                        o_unique_number <= number_storage[count-1];
                    end
                end
                default: begin
                    o_unique_number <= 0;
                    count <= 0;
                end
            endcase
        end
    end

endmodule

