output.rtl/sorting_engine.sv:
module sorting_engine #(parameter WIDTH = 8, parameter N = 8) (
    input clk,
    input rst,
    input start,
    input [N*WIDTH-1:0] in_data,
    output reg done,
    output reg [N*WIDTH-1:0] out_data
);

    // State declaration
    localparam IDLE = 2'b00,
              SORTING = 2'b01,
              DONE = 2'b10;

    // State register
    reg [2:0] state_reg, state_next;

    // Counter for the number of passes
    reg [N-1:0] pass_count;

    // Internal signals for comparison and swapping
    logic [WIDTH-1:0] temp;

    // State transition logic
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state_reg <= IDLE;
            pass_count <= 0;
            out_data <= {WDATA{1'b0}}; // Uninitialized output
            done <= 1'b0;
        end else if (start && state_reg == IDLE) begin
            state_reg <= SORTING;
            pass_count <= 0;
            out_data <= {WDATA{1'b0}}; // Uninitialized output
            done <= 1'b0;
        end else if (state_reg == SORTING) begin
            pass_count <= pass_count + 1;
            if (pass_count == N-1) begin
                state_next = DONE;
            end else begin
                state_next = SORTING;
            end
        end else if (state_reg == DONE) begin
            state_next = IDLE;
        end
        state_reg <= state_next;
    end

    // Bubble sort implementation
    always @(posedge clk) begin
        if (state_reg == SORTING) begin
            for (int i = 0; i < N-1; i++) begin
                if (in_data[i*WIDTH] > in_data[i*WIDTH + 1]) begin
                    temp = in_data[i*WIDTH];
                    in_data[i*WIDTH] = in_data[i*WIDTH + 1];
                    in_data[i*WIDTH + 1] = temp;
                end
            end
        end
    end

    // Output assignment
    always @(state_reg == DONE) begin
        out_data <= in_data;
        done <= 1'b1;
    end

endmodule

input.rtl/sorting_engine.sv:
module sorting_engine #(
    parameter N = 8,             // Number of elements to sort
    parameter WIDTH = 8          // Bit-width of each element
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // Internal registers to hold the array
    reg [WIDTH-1:0] array [0:N-1];

    // FSM states
    localparam IDLE    = 2'd0;
    localparam SORTING = 2'd1;
    localparam DONE    = 2'd2;

    reg [1:0]  state, next_state;

    // Variables for bubble sort indexing
    reg [$clog2(N)-1:0] i;  // Outer loop index
    reg [$clog2(N)-1:0] j;  // Inner loop index

    // Wires for comparison and swap
    wire [WIDTH-1:0] val_j;
    wire [WIDTH-1:0] val_j1;

    assign val_j  = array[j];
    assign val_j1 = array[j+1];

    // FSM: Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                // Transition to DONE once all passes are complete
                if (i == (N-1) && j == (N-2))
                    next_state = DONE;
            end
            DONE: begin
                next_state = IDLE;
            end
            default: begin
                next_state = IDLE;
