module sorting_engine #(
    parameter N = 8,     
    parameter WIDTH = 8  
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);
    localparam IDLE = 2'd0,
               LOAD = 2'd1,
               SORT = 2'd2,
               DONE = 2'd3;

    reg [1:0]  state, next_state;
    reg [WIDTH-1:0] data_array [0:N-1];
    reg [$clog2(N+1)-1:0] pass_cnt;
    reg [$clog2(N/2+1)-1:0] pair_idx;

    wire [$clog2(N/2+1)-1:0] pairs_in_this_pass;
    assign pairs_in_this_pass = (pass_cnt[0] == 1'b0) ? (N/2) : ( (N/2) > 0 ? (N/2) - 1 : 0 );

    // Initialize the data array
    always @(posedge clk) begin
        if (rst) begin
            state <= IDLE;
            data_array <= {WIDTH{in_data[0]}};
        end else if (start) begin
            state <= LOAD;
        end
    end

    // State machine
    always @(state, pair_idx) begin
        case (state)
            IDLE: begin
                if (pair_idx == N - 1) begin
                    state <= SORT;
                    pass_cnt <= 0;
                end
            end
            LOAD: begin
                if (pair_idx < N - 1) begin
                    data_array <= {data_array[pair_idx], data_array[pair_idx + 1]};
                    pair_idx <= pair_idx + 1;
                end
            end
            SORT: begin
                if (pass_cnt == N - 1) begin
                    state <= DONE;
                    out_data <= data_array;
                    done <= 1'b1;
                end else if (pair_idx < N - 1) begin
                    case (pair_idx % 2 == 0)
                        0: begin
                            if (data_array[pair_idx] > data_array[pair_idx + 1]) begin
                                data_array[pair_idx] <= data_array[pair_idx + 1];
                                data_array[pair_idx + 1] <= data_array[pair_idx];
                            end
                        end
                        1: begin
                            if (data_array[pair_idx] > data_array[pair_idx + 2]) begin
                                data_array[pair_idx] <= data_array[pair_idx + 2];
                                data_array[pair_idx + 2] <= data_array[pair_idx];
                            end
                        end
                    end
                    pair_idx <= pair_idx + (2 * (pair_idx % 2));
                    pass_cnt <= pass_cnt + 1;
                end
            end
            DONE: begin
                state <= IDLE;
            end
        end
    end
endmodule

always @(posedge clk or posedge rst) begin
    if (rst) begin
        // synchronous reset
        current_state <= S_IDLE;
        done          <= 1'b0;
        out_data      <= {N*WIDTH{1'b0}};
        max_val       <= {WIDTH{1'b0}};

        load_cnt      <= 0;
        find_cnt      <= 0;
        count_cnt     <= 0;
        prefix_cnt    <= 0;
        build_cnt     <= 0;
        copy_cnt      <= 0;

        // Clear arrays
        for (i = 0; i < N; i = i + 1) begin
            data_array[i] <= {WIDTH{1'b0}};
            out_array[i]  <= {WIDTH{1'b0}};
        end
        for (i = 0; i < (1<<WIDTH); i = i + 1) begin
            count_array[i] <= {($clog2(N)+1){1'b0}};
        end
    end else begin
        case (current_state)
            S_IDLE: begin
                if (start) begin
                    current_state <= S_LOAD_INPUT;
                end else begin
                    current_state <= S_IDLE;
                end
            end
            S_LOAD_INPUT: begin
                if (!start) begin
                    current_state <= S_IDLE;
                end else begin
                    for (i = 0; i < N; i = i + 1) begin
                        data_array[i] <= in_data[i*WIDTH +: WIDTH];
                    end
                    next_data_array <= data_array;
                    load_cnt <= N;
                    next_load_cnt <= N;
                    next_state <= S_FIND_MAX;
                end
            end
            S_FIND_MAX: begin
                max_val <= {WIDTH{data_array[N-1]}};
                next_max_val <= max_val;
                next_state <= S_COUNT;
            end
            S_COUNT: begin
                count_array <= {(1<<WIDTH)-1'b0, 0};
                for (i = 0; i < (1<<WIDTH); i = i + 1) begin
                    count_array[i] <= count_array[i] + (next_data_array[i] == next_max_val);
                end
                next_count_array <= count_array;
                find_cnt <= N;
                next_state <= S_PREFIX_SUM;
            end
            S_PREFIX_SUM: begin
                prefix_cnt <= {$clog2(N)+1{1'b0}};
                for (i = 0; i < prefix_cnt; i = i + 1) begin
                    count_array[i] <= count_array[i] + count_array[i+1];
                end
                next_prefix_cnt <= prefix_cnt;
                next_state <= S_BUILD_OUTPUT;
            end
            S_BUILD_OUTPUT: begin
                build_cnt <= N;
                for (i = 0; i < N; i = i + 1) begin
                    out_array[i] <= (count_array[count_array[i]] == count_array[0]) ? (max_val - 1) : (max_val);
                end
                next_out_array <= out_array;
                copy_cnt <= N;
                next_state <= S_COPY_OUTPUT;
            end
            S_COPY_OUTPUT: begin
                out_data <= next_out_data;
                next_out_data <= {N*WIDTH{1'b0}};
                copy_cnt <= N;
                next_done <= 1'b0;
                current_state <= S_DONE;
            end
            S_DONE: begin
                done <= next_done;
                next_state <= S_IDLE;
            end
        end
    end
end

always @* begin
    // Combinational logic for state transitions
    next_state = current_state;
    if (current_state == S_IDLE) begin
        next_max_val <= {WIDTH{1'b0}};
        next_load_cnt <= 0;
        next_find_cnt <= 0;
        next_count_cnt <= 0;
        next_prefix_cnt <= 0;
        next_build_cnt <= 0;
        next_copy_cnt <= 0;
        next_done <= 1'b0;
    end else if (current_state == S_LOAD_INPUT) begin
        next_max_val <= max_val;
        next_load_cnt <= load_cnt;
        next_find_cnt <= find_cnt;
        next_count_cnt <= count_cnt;
        next_prefix_cnt <= prefix_cnt;
        next_build_cnt <= build_cnt;
        next_copy_cnt <= copy_cnt;
    end else if (current_state == S_FIND_MAX) begin
        next_max_val <= max_val;
        next_load_cnt <= 1;
        next_find_cnt <= 0;
        next_count_cnt <= 0;
        next_prefix_cnt <= 0;
        next_build_cnt <= 0;
        next_copy_cnt <= 0;
    end else if (current_state == S_COUNT) begin
        next_max_val <= max_val;
        next_load_cnt <= 0;
        next_find_cnt <= 1;
        next_count_cnt <= count_cnt + 1;
        next_prefix_cnt <= 0;
        next_build_cnt <= 0;
        next_copy_cnt <= 0;
    end else if (current_state == S_PREFIX_SUM) begin
        next_max_val <= max_val;
        next_load_cnt <= 0;
        next_find_cnt <= 0;
        next_count_cnt <= count_cnt + 1;
        next_prefix_cnt <= prefix_cnt + 1;
        next_build_cnt <= 0;
        next_copy_cnt <= 0;
    end else if (current_state == S_BUILD_OUTPUT) begin
        next_max_val <= max_val;
        next_load_cnt <= 0;
        next_find_cnt <= 0;
        next_count_cnt <= count_cnt;
        next_prefix_cnt <= prefix_cnt;
        next_build_cnt <= build_cnt + 1;
        next_copy_cnt <= copy_cnt;
    end else if (current_state == S_COPY_OUTPUT) begin
        next_max_val <= max_val;
        next_load_cnt <= 0;
        next_find_cnt <= 0;
        next_count_cnt <= count_cnt;
        next_prefix_cnt <= prefix_cnt;
        next_build_cnt <= 0;
        next_copy_cnt <= copy_cnt + 1;
    end
end

