module sorting_engine #(
    parameter N = 8,             // Number of elements to sort
    parameter WIDTH = 8          // Bit-width of each element
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // Internal array
    reg [WIDTH-1:0] array [0:N-1];

    // FSM states
    localparam IDLE    = 2'd0;
    localparam SORTING = 2'd1;
    localparam DONE    = 2'd2;

    reg [1:0] state, next_state;

    // Insertion sort variables
    integer i;
    integer j;
    reg [WIDTH-1:0] key;

    // FSM: Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                // Once i reaches N, sorting is done
                if (i == N)
                    next_state = DONE;
            end
            DONE: begin
                next_state = IDLE;
            end
            default: next_state = IDLE;
        endcase
    end

    // FSM: main logic
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state         <= IDLE;
            done          <= 0;
            i             <= 0;
            j             <= 0;
            key           <= 0;
        end else begin
            state <= next_state;

            case (state)
                IDLE: begin
                    done <= 0;
                    if (start) begin
                        // Load array from in_data with less wiring
                        for (int k = 0; k < N; k = k + 1) begin
                            array[k] <= {in_data[(k+1)*WIDTH-1], in_data[(k+2)*WIDTH-1]};
                        end
                        i <= 1;
                        j <= 0;
                        key <= 0;
                    end
                end

                SORTING: begin
                    // Perform insertion sort step-by-step
                    case (insert_phase)
                        0: begin
                            // Phase 0: Setup for inserting array[i]
                            if (i < N) begin
                                key <= array[i][WIDTH-1];
                                j <= i - 1;
                                insert_phase <= 1;
                            end
                            // If i == N, sorting complete
                        end

                        1: begin
                            // Phase 1: Shift elements to the right until the correct spot is found
                            if (j >= 0 && array[j][WIDTH-1] > key) begin
                                array[j+1] <= {array[j][WIDTH-1], array[j][WIDTH-1]};
                                j <= j - 1;
                            end else begin
                                // We found the spot (or j < 0)
                                insert_phase <= 2;
                            end
                        end

                        2: begin
                            // Phase 2: Insert the key at array[j+1]
                            array[j+1] <= {key, array[j+1][WIDTH-1]};
                            i <= i + 1;
                            insert_phase <= 0; 
                        end

                        default: insert_phase <= 0;
                    endcase
                end

                DONE: begin
                    // Sorting complete, output the result
                    done <= 1;
                    for (int m = 0; m < N; m = m + 1) begin
                        out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                    end
                end

                default: begin
                    // Should not get here
                end
            endcase
        end
    end

endmodule

output.rtl/soundgenerator.sv:
module soundgenerator #(
	parameter  CLOCK_HZ = 10_000_000
)(
	input wire clk,                                         //input clock signal with frequency 10Mhz
	input wire nrst,                                        //active low asynchronous reset.

	input wire start,                                       //indicate the start of the operation.
	input wire finish,                                      //indicate the end of operation.
	input wire [15:0] sond_dur_ms_i,                        //this signal indicate for how much time the sound should be generated in millisecond.
	input wire [15:0] half_period_us_i,                     //this signal indicate the frequency of the output signal by giving the half time period required for the output soundwave_o 

	output wire soundwave_o,                                //output sound wave signal.
	output wire busy,                                       //indicate the system is busy.
	output wire done                                        //indicate the operation is completed.
);

// Internal timing generators
wire [15:0] tick_milli_clk;
wire [15:0] tick_micro_clk;

// Generate TickMilli
strob_gen #(.CLOCK_HZ(CLOCK_HZ / 1000)) tMilli(.clk(clk), .nrst(1'b1), .enable(1'b1), .strobe_o(tick_milli_clk));

// Generate tickmicro
strob_gen #(.CLOCK_HZ(CLOCK_HZ * 1000), .PERIOD_US(1)) tMicro(.clk(clk), .nrst(1'b1), .enable(1'b1), .strobe_o(tick_micro_clk));

// Duration Timer
reg [15:0] duration_counter;
always @(posedge clk) begin
    if (!nrst) begin
        duration_counter <= 16'd0;
    end else begin
        if (start) begin
            duration_counter <= sond_dur_ms_i;
        end
        if (duration_counter > 0) begin
            duration_counter <= duration_counter - 1;
        end
    end
end

// Soundwave Signal Generation
reg [15:0] halfperiod_counter;
wire [15:0] soundwave_pattern;
wire soundwave_active;

always @(posedge clk) begin
    if (start && !nrst) begin
        halfperiod_counter <= half_period_us_i;
        soundwave_active <= 1'b0;
    end
    if (enable && soundwave_active) begin
        if (tick_micro_clk == 1'b1) begin
            if (halfperiod_counter > 0) begin
                halfperiod_counter <= halfperiod_counter - 1;
                soundwave_active <= ~soundwave_active;
            end
        end
    end
end

// Connect soundwave_o with soundwave_active
assign soundwave_o = soundwave_active & (soundwave_active != 1'b1);

// Busy and Done signals
reg busy_reg;
reg done_reg;

// Internal function to manage busy and done signals
always @(posedge clk) begin
    if (start && !nrst) begin
        busy_reg <= 1'b1;
        done_reg <= 1'b0;
    end
    if (done_reg) begin
        busy_reg <= 1'b0;
    end
    if (duration_counter == 0) begin
        busy_reg <= 1'b0;
        done_reg <= 1'b1;
    end
end

// Outputs
assign busy = busy_reg;
assign done = done_reg;

endmodule

module strob_gen #(
	parameter	CLOCK_HZ	= 10_000_000,
	parameter	PERIOD_US	= 100
)(
	input wire  clk,
	input wire  nrst,
	input wire  enable,
	output reg  strobe_o
);

// Calculate delay based on clock frequency and desired period
wire [15:0] delay;
assign delay = (CLOCK_HZ * PERIOD_US) / 1_000_000;

// Counter and strobe signal generation
reg [PERIOD_US - 1:0] counter;
always @(posedge clk) begin
    if (nrst) begin
        counter <= 16'd0;
    end else begin
        if (enable) begin
            if (counter == 0) begin
                counter <= delay;
                strobe_o <= 1'b1;
            end else begin
                counter <= counter - 1;
                strobe_o <= 1'b0;
            end
        end
    end
end

endmodule

output.rtl/sprite_fsm.sv:
// FSM code
always @(posedge clk or posedge rst_n) begin
    if (rst_n) begin
        current_state <= IDLE;
        addr_counter <= (0 >> MEM_ADDR_WIDTH-1) << MEM_ADDR_WIDTH-1; // Reset to 0
        data_counter <= (0 >> PIXEL_WIDTH-1) << PIXEL_WIDTH-1;     // Reset to 0
        wait_counter <= (0 >> WAIT_WIDTH-1) << WAIT_WIDTH-1;       // Reset to 0
    end else begin
        case (current_state)
            IDLE: begin
                rw <= 0; // Set to read mode
                next_state <= INIT_WRITE;
            end
            INIT_WRITE: begin
                addr_counter <= 0;
                data_counter <= 24'hFF0000; // Initial data value
                rw <= 1; // Set to write mode
                next_state <= WRITE;
            end
            WRITE: begin
                if (addr_counter == N_ROM - 1) begin
                    next_state <= INIT_READ;
                end else begin
                    next_state <= WRITE;
                end
            end
            INIT_READ: begin
                addr_counter <= 0;
                rw <= 0; // Set to read mode
                next_state <= READ;
            end
            READ: begin
                x_pos <= (addr_counter >> (SPRITE_WIDTH * (PIXEL_WIDTH - 1) - 1)) & ((1 << SPRITE_WIDTH) - 1);
                y_pos <= (addr_counter >> (PIXEL_WIDTH - 1)) & ((1 << SPRITE_HEIGHT) - 1);
                write_addr <= addr_counter;
                next_state <= WAIT;
            end
            WAIT: begin
                if (wait_counter >= i_wait) begin
                    done <= 1;
                    next_state <= DONE;
                end else begin
                    next_state <= WAIT;
                end
            end
            DONE: begin
                done <= 0;
                next_state <= IDLE;
            end
        endcase
    end
end

// Signal generation
assign x_pos = (addr_counter >> (SPRITE_WIDTH * (PIXEL_WIDTH - 1) - 1)) & ((1 << SPRITE_WIDTH) - 1);
assign y_pos = (addr_counter >> (PIXEL_WIDTH - 1)) & ((1 << SPRITE_HEIGHT) - 1);

// Output assignments
assign write_addr = addr_counter;
assign write_data = data_counter;
assign done = 1; // For one clock cycle

