module square_root #(parameter WIDTH = 16) (
    input  wire [WIDTH-1:0] num,       
    output reg  [WIDTH/2-1:0] root     
);
    reg [WIDTH-1:0] remainder,square;         
    reg [WIDTH/2-1:0] test_bit, temp_square;        
    integer i,j;

    always @(*) 
    begin
        remainder = num;               
        root = 0;                      
        temp_square = 0;


        for (i = WIDTH/2-1; i >= 0; i = i - 1) 
        begin
            test_bit = 1'b1 << i;      
            temp_square = (root | test_bit);        
            square = 0; 
            for (j = 0; j < WIDTH; j = j + 1) 
            begin
              if (temp_square[j]) 
              begin 
                  square = square + (temp_square << j); 
              end 
            end

            if (square <= remainder) 
            begin
                root = root | test_bit; 
            end
        end
    end
endmodule

output.rtl/square_root_seq.sv:
module square_root_seq #(parameter WIDTH = 16) (
    input  wire clk,
    input  wire rst,
    input  wire start,
    input  wire [WIDTH-1:0] num,
    output reg [WIDTH/2-1:0] final_root,
    output reg done
);
    reg [WIDTH-1:0] remainder, current_odd;
    reg [WIDTH/2-1:0] square_root;

    // State machine initialization
    initial begin
        remainder = num;
        square_root = 0;
        current_odd = 1;
        done = 0;
    end

    // State machine logic
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            // Asynchronous reset
            remainder <= 0;
            current_odd <= 1;
            square_root <= 0;
            done <= 0;
        end else if (start) begin
            // Synchronized reset and start
            remainder <= num;
            current_odd <= 1;
            square_root <= 0;
            done <= 0;
        end else if (done) begin
            // IDLE state
            final_root <= 0;
        end else if (remainder >= current_odd) begin
            // COMPUTE state
            square_root <= square_root + 1;
            remainder <= remainder - current_odd;
            current_odd <= current_odd + 2;
            if (remainder < current_odd) begin
                // Computation complete
                final_root <= square_root;
                done <= 1;
            end
        end
    end

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict(
    input [31:0] fetch_rdata_i,
    input [31:0] fetch_pc_i,
    input fetch_valid_i,
    output reg predict_branch_taken_o,
    output [31:0] predict_branch_pc_o
);

    reg [31:0] imm_j_type, imm_b_type, imm_cj_type, imm_cb_type;
    logic instr_j, instr_b, instr_cj, instr_cb;
    logic instr_b_taken;

    always_comb {
        // Instruction type decoding
        imm_j_type = (fetch_rdata_i == 32'h6F); // JAL
        imm_b_type = (fetch_rdata_i == 32'h63); // BXXX
        imm_cj_type = (fetch_rdata_i == 32'h67); // C.J
        imm_cb_type = (fetch_rdata_i == 32'h63); // C.J

        // Sign extension
        imm_b_type = {31'b0, imm_b_type[30:0], fetch_rdata_i[31]};
        imm_cj_type = {31'b0, imm_cj_type[30:0], fetch_rdata_i[31]};

        // Uncompressed Branch/Jump Detection
        instr_j = (imm_cj_type == 32'h67);
        instr_b = (imm_b_type == 32'h63) | (imm_cj_type == 32'h67);

        // Compressed Branch/Jump Detection
        instr_cb = (fetch_valid_i && (fetch_rdata_i == {19'b0, 18'h0, 12'h0, imm_cb_type[11:0]});

        // Offset-Based Prediction
        instr_b_taken = (imm_b_type[31] == 1);

        // Prediction Logic
        predict_branch_taken_o = (instr_j || instr_cb) || instr_b_taken;
        predict_branch_pc_o = (predict_branch_taken_o) ? fetch_pc_i + imm_b_type : 32'h0;
    }
endmodule

