module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;


  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0};

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : ;
    endcase
  end
  assign predict_branch_pc_o    = fetch_pc_i + branch_imm; 
  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);
  assign predict_branch_taken_o = fetch_valid_i & (instr_jal | instr_jalr | instr_cj | instr_b_taken);

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction outputs
  output logic [7:0] predict_confidence_o,
  output logic [1:0] predict_exception_o,
  output logic [3:0] predict_branch_type_o,
  output logic [31:0] predict_branch_offset_o,

  // Instruction types
  output logic [31:0] imm_jal_type,
  output logic [31:0] imm_jalr_type,
  output logic [31:0] imm_b_type,
  output logic [31:0] imm_cj_type,
  output logic [31:0] imm_cb_type,

  output logic predict_branch_taken_o,

  // Branch prediction logic
  always_comb begin
    case(fetch_valid_i)
     1'b1 : begin
        // Jump instructions
        if (instr[1:0] == 3'b001 || instr[1:0] == 3'b010) begin
          predict_branch_type_o = {3'b011, fetch_rdata_i[15:13]};
          if (fetch_rdata_i[15:13] == 3'b110 || fetch_rdata_i[15:13] == 3'b111) begin
            predict_branch_taken_o = 1'b1;
            predict_confidence_o = 8'd90;
          end else begin
            predict_branch_taken_o = 1'b0;
            predict_confidence_o = 8'd50;
          end
        end else if (fetch_rdata_i[15:13] == 3'b101 || fetch_rdata_i[15:13] == 3'b001) begin
            predict_branch_taken_o = 1'b1;
            predict_confidence_o = 8'd90;
          end else begin
            predict_branch_taken_o = 1'b0;
            predict_confidence_o = 8'd50;
          end
        end
      end
      // Branch instructions
      default: begin
        if (instr[1:0] == OPCODE_BRANCH) begin
          imm_b_type = {{19{fetch_rdata_i[31]}},fetch_rdata_i[31],fetch_rdata_i[7],fetch_rdata_i[30:25],fetch_rdata_i[11:8],1'b0};
          if (imm_b_type[31] == 1) begin
            predict_branch_taken_o = 1'b1;
            predict_confidence_o = 8'd90;
          end else begin
            predict_branch_taken_o = 1'b0;
            predict_confidence_o = 8'd50;
          end
        end else if (imm_b_type[31] == 0) begin
          predict_branch_taken_o = 1'b0;
          predict_confidence_o = 8'd50;
        end
        // Compressed branch instructions
        else if (fetch_rdata_i[15:13] == 3'b100 || fetch_rdata_i[15:13] == 3'b101) begin
          imm_cb_type = {{23{fetch_rdata_i[12]}},fetch_rdata_i[12],fetch_rdata_i[31],fetch_rdata_i[7],fetch_rdata_i[30:25],fetch_rdata_i[11:8],1'b0};
          if (imm_cb_type[31] == 1) begin
            predict_branch_taken_o = 1'b1;
            predict_confidence_o = 8'd90;
          end else begin
            predict_branch_taken_o = 1'b0;
            predict_confidence_o = 8'd50;
          end
        end
        // Invalid or unrecognized instructions
        else if (!fetch_valid_i) begin
          predict_branch_taken_o = 1'b0;
          predict_confidence_o = 8'd0;
        end
      end
    end
  end

  // Immediate Extraction
  assign imm_jal_type = {{20{instr[31]}},instr[31:20]}+register_addr_i;
  assign imm_jalr_type = {{20{instr[31]}},instr[31:20];
  assign imm_cj_type = { {20{instr[12]}},instr[12],instr[8],instr[10:9],instr[6],instr[7],
    instr[2],instr[11],instr[5:3],1'b0};
  assign imm_cb_type = {{23{instr[12]}},instr[12],instr[6:5],instr[2],instr[11:10],
    instr[4:3],1'b0};

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;
);

  // Instruction Decoding
  always @(*) begin
    instr = fetch_rdata_i;
    instr_jal = (instr[6:0] == 7'h6F);
    instr_jalr = (instr[6:0] == 7'h67);
    instr_b = (instr[6:0] == 7'h63);
    instr_cj = (instr[15:12] == 7'h00000000);
    instr_cb = (instr[15:12] == 7'h00000001);
  end

  // Branch Immediate Selection
  always @(*) begin
    imm_jal_type = {31{instr_jal}};
    imm_jalr_type = imm_jal_type + {reg_addr};
    imm_b_type = {31{instr_b}};
    imm_cj_type = {31{instr_cj}};
    imm_cb_type = {31{instr_cb}};
    branch_imm = (instr_jal) || (instr_jalr) || (instr_b) ? imm_jal_type :
                 (instr_cj) ? imm_cj_type :
                 (instr_cb) ? imm_cb_type : imm_b_type;
  end

  // Branch Taken Decision
  always @(*) begin
    instr_b_taken = (instr_b) ? imm_b_type[31] : 0;
    // Assuming similar logic for imm_cj_type and imm_cb_type if needed
  end

  // Branch Prediction
  assign predict_branch_taken_o = (instr_jal) || (instr_jalr) || (instr_b) || (instr_cj) || (instr_cb);

  // Branch Target Address Calculation
  assign predict_branch_pc_o = fetch_pc_i + branch_imm;

endmodule

// Branch prediction and branch target calculation
always @(fetch_rdata_i, fetch_pc_i, register_addr_i, fetch_valid_i) begin
  instr <= fetch_rdata_i;

  // Instruction type decoding
  instr_jal = (instr[6:0] == 7'h6F);
  instr_jalr = (instr[6:0] == 7'h67);
  instr_b = (instr[6:0] == 7'h63);
  instr_cj = (instr[19:12] == 7'h0000000); // Assuming specific bits for CJ
  instr_cb = (instr[19:12] == 7'h0000001); // Assuming specific bits for CB

  // Calculate immediate values based on instruction type
  if (instr_jal) begin
    imm_jal_type = { {12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
    predict_confidence_o = 100;
  end
  else if (instr_jalr) begin
    imm_jalr_type = {{20{instr[31]}}, instr[31:20]} + register_addr;
    predict_confidence_o = 100;
  end
  else if (instr_b) begin
    imm_b_type =  { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };
    if (imm_b_type[31]) begin
      predict_confidence_o = 90;
      predict_b_taken_o = 1;
    end
    else begin
      predict_confidence_o = 50;
      predict_b_taken_o = 0;
    end
  end
  else if (instr_cj) begin
    imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7], instr[2], instr[11], instr[5:3], 1'b0 };
    if (imm_cj_type[31]) begin
      predict_confidence_o = 90;
      predict_cj_taken_o = 1;
    end
    else begin
      predict_confidence_o = 50;
      predict_cj_taken_o = 0;
    end
  end
  else if (instr_cb) begin
    imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10], instr[4:3], 1'b0 };
    if (imm_cb_type[31]) begin
      predict_confidence_o = 90;
      predict_cb_taken_o = 1;
    end
    else begin
      predict_confidence_o = 50;
      predict_cb_taken_o = 0;
    end
  end
  else begin
    predict_confidence_o = 0;
    predict_branch_taken_o = 0;
    predict_exception_o = 1; // Assuming misalignment for invalid instructions
  end

  // Calculate branch offset
  if (instr_jal || instr_jalr || instr_b || instr_cj || instr_cb) begin
    predict_branch_offset_o = predict_branch_pc_o + (imm_jal_type || imm_jalr_type || imm_b_type || imm_cj_type || imm_cb_type);
  end
  else begin
    predict_branch_offset_o = 0;
  end
end

