module vending_machine (
    input clk,
    input rst,
    input item_button,
    input [2:0] item_selected,
    input [3:0] coin_input,
    input cancel,
    output reg dispense_item,
    output reg return_change,
    output [4:0] item_price,
    output [4:0] change_amount,
    output [2:0] dispense_item_id,
    output error,
    output return_money
);

    // State declarations
    localparam IDLE = 2'b00,
              ITEM_SELECTION = 2'b01,
              PAYMENT_VALIDATION = 2'b10,
              DISPENSING_ITEM = 2'b11;

    // Internal state register
    reg [2:0] current_state, next_state;
    reg [4:0] coins_accumulated = 0;
    reg [4:0] item_price_display = 0;
    reg [4:0] change_to_return = 0;

    // State transition logic
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            current_state <= IDLE;
            coins_accumulated <= 0;
            item_price_display <= 0;
            change_to_return <= 0;
        end else begin
            current_state <= next_state;
        end
    end

    // State transition conditions
    always @(current_state or item_selected or coin_input or cancel) begin
        case (current_state)
            IDLE: begin
                if (item_button) begin
                    next_state <= ITEM_SELECTION;
                end else begin
                    next_state <= IDLE;
                end
            end
            ITEM_SELECTION: begin
                if (item_selected >= 3'b001 && item_selected <= 3'b100) begin
                    next_state <= PAYMENT_VALIDATION;
                    item_price_display <= {item_selected[2:0], 4'b0000}; // Example prices, replace with actual prices
                end else begin
                    next_state <= RETURN_MONEY;
                end
            end
            PAYMENT_VALIDATION: begin
                if (coin_input == 4'b0000 || coin_input == 4'b0001 || coin_input == 4'b0100 || coin_input == 4'b1000) begin
                    coins_accumulated <= coins_accumulated + coin_input;
                    if (coins_accumulated >= item_price_display) begin
                        next_state <= DISPENSING_ITEM;
                    end else begin
                        next_state <= PAYMENT_VALIDATION;
                    end
                end else begin
                    error <= 1'b1;
                    next_state <= RETURN_MONEY;
                end
            end
            DISPENSING_ITEM: begin
                dispense_item <= 1'b1;
                if (coins_accumulated > item_price_display) begin
                    change_to_return <= coins_accumulated - item_price_display;
                    next_state <= RETURN_CHANGE;
                end else begin
                    next_state <= IDLE;
                end
            end
            RETURN_CHANGE: begin
                return_change <= 1'b1;
                next_state <= IDLE;
            end
            RETURN_MONEY: begin
                return_money <= 1'b1;
                next_state <= IDLE;
            end
            default: begin
                next_state <= IDLE;
            end
        end
    end

    // Output logic
    always @(current_state or dispense_item or return_change or item_price_display or change_to_return or return_money or error) begin
        case (current_state)
            IDLE: begin
                dispense_item <= 0;
                return_change <= 0;
                item_price_display <= 0;
                change_to_return <= 0;
                dispense_item_id <= 0;
                error <= 0;
                return_money <= 0;
            end
            ITEM_SELECTION: begin
                dispense_item <= 0;
                return_change <= 0;
                item_price_display <= item_price_display;
                change_to_return <= 0;
                dispense_item_id <= item_selected;
                error <= 0;
                return_money <= 0;
            end
            PAYMENT_VALIDATION: begin
                dispense_item <= 0;
                return_change <= 0;
                item_price_display <= item_price_display;
                change_to_return <= 0;
                dispense_item_id <= 0;
                error <= 0;
                return_money <= 0;
            end
            DISPENSING_ITEM: begin
                dispense_item <= 1;
                return_change <= 0;
                item_price_display <= item_price_display;
                change_to_return <= 0;
                dispense_item_id <= dispense_item_id;
                error <= 0;
                return_money <= 0;
            end
            RETURN_CHANGE: begin
                dispense_item <= 0;
                return_change <= 1;
                item_price_display <= 0;
                change_to_return <= change_to_return;
                dispense_item_id <= 0;
                error <= 0;
                return_money <= 0;
            end
            RETURN_MONEY: begin
                dispense_item <= 0;
                return_change <= 0;
                item_price_display <= 0;
                change_to_return <= 0;
                dispense_item_id <= 0;
                error <= 0;
                return_money <= 1;
            end
            default: begin
                dispense_item <= 0;
                return_change <= 0;
                item_price_display <= 0;
                change_to_return <= 0;
                dispense_item_id <= 0;
                error <= 1;
                return_money <= 0;
            end
        end
    end
endmodule

output.rtl/vga_controller.sv:
module vga_controller(
    input clk,
    input reset,
    input [7:0] color_in,
    output reg hsync,
    output reg vsync,
    output reg [7:0] red,
    output reg [7:0] green,
    output reg [7:0] blue,
    output reg [9:0] next_x,
    output reg [9:0] next_y,
    output reg sync,
    output reg clk,
    output reg blank
);

    // State definitions for horizontal and vertical state machines
    typedef enum logic [31:0] {
        H_ACTIVE,
        H_FRONT,
        H_PULSE,
        H_BACK
    } h_state_t;

    typedef enum logic [31:0] {
        V_ACTIVE,
        V_FRONT,
        V_PULSE,
        V_BACK
    } v_state_t;

    // State machines
    reg [31:0] h_state, v_state;

    // Counters
    reg [9:0] h_counter = 0, v_counter = 0;

    // Parameters
    localparam H_ACTIVE_CNT = 640;
    localparam H_FRONT_CNT = 16;
    localparam H_PULSE_CNT = 96;
    localparam H_BACK_CNT = 48;

    localparam V_ACTIVE_CNT = 480;
    localparam V_FRONT_CNT = 10;
    localparam V_PULSE_CNT = 2;
    localparam V_BACK_CNT = 33;

    // State transition logic
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            h_state <= H_ACTIVE;
            v_state <= V_ACTIVE;
            h_counter <= 0;
            v_counter <= 0;
            line_done <= 1'b0;
            sync <= 1'b0;
            blank <= 1'b0;
        end else begin
            case (h_state)
                H_ACTIVE: begin
                    if (h_counter == H_ACTIVE_CNT) begin
                        h_state <= H_FRONT;
                        line_done <= 1'b0;
                    end else begin
                        h_counter <= h_counter + 1;
                    end
                end
                H_FRONT: begin
                    if (h_counter == H_FRONT_CNT) begin
                        h_state <= H_PULSE;
                        line_done <= 1'b0;
                    end else begin
                        h_counter <= h_counter + 1;
                    end
                end
                H_PULSE: begin
                    if (h_counter == H_PULSE_CNT) begin
                        h_state <= H_BACK;
                        line_done <= 1'b0;
                    end else begin
                        h_counter <= h_counter + 1;
                    end
                end
                H_BACK: begin
                    if (h_counter == H_BACK_CNT) begin
                        h_state <= H_ACTIVE;
                        line_done <= 1'b0;
                    end else begin
                        h_counter <= h_counter + 1;
                    end
                end
                default: h_state <= H_ACTIVE;
            endcase

            case (v_state)
                V_ACTIVE: begin
                    if (v_counter == V_ACTIVE_CNT) begin
                        v_state <= V_FRONT;
                        next_y <= next_y + 1;
                    end else begin
                        v_counter <= v_counter + 1;
                    end
                end
                V_FRONT: begin
                    if (v_counter == V_FRONT_CNT) begin
                        v_state <= V_PULSE;
                        next_x <= next_x + 1;
                    end else begin
                        v_counter <= v_counter + 1;
                    end
                end
                V_PULSE: begin
                    if (v_counter == V_PULSE_CNT) begin
                        v_state <= V_BACK;
                        next_y <= next_y + 1;
                    end else begin
                        v_counter <= v_counter + 1;
                    end
                end
                V_BACK: begin
                    if (v_counter == V_BACK_CNT) begin
                        v_state <= V_ACTIVE;
                        next_x <= next_x + 1;
                    end else begin
                        v_counter <= v_counter + 1;
                    end
                end
                default: v_state <= V_ACTIVE;
            endcase
        end

        // RGB signal assignment
        always_comb begin
            if (h_state == H_ACTIVE || v_state == V_ACTIVE) begin
                red <= color_in[7:5];
                green <= color_in[4:2];
                blue <= color_in[1:0];
            end else begin
                red <= 8'd0;
                green <= 8'd0;
                blue <= 8'd0;
            end
        end

        // Sync signal assignment
        always_comb begin
            sync <= 1'b0;
            if (h_state == H_PULSE || v_state == V_PULSE) begin
                sync <= 1'b1;
            end

        // Blanking signal logic
        always_comb begin
            blank <= hsync | vsync;
        end
    endmodule

module vga_controller (
    input logic clock,      // 25 MHz
    input logic reset,      // Active high
    input logic [7:0] color_in, // Pixel color data (RRRGGGBB)
    output logic [9:0] next_x,  // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0] next_y,  // y-coordinate of NEXT pixel that will be drawn
    output logic hsync,     // HSYNC (to VGA connector)
    output logic vsync,     // VSYNC (to VGA connector)
    output logic [7:0] red, // RED (to resistor DAC VGA connector)
    output logic [7:0] green, // GREEN (to resistor DAC to VGA connector)
    output logic [7:0] blue, // BLUE (to resistor DAC to VGA connector)
    output logic sync,      // SYNC to VGA connector
    output logic clk,       // CLK to VGA connector
    output logic blank,      // BLANK to VGA connector
    output logic [7:0] h_state, // States of Horizontal FSM
    output logic [7:0] v_state, // States of Vertical FSM
);

    parameter logic [9:0] H_ACTIVE  =  10'd640;
    parameter logic [9:0] H_FRONT   =  10'd16;
    parameter logic [9:0] H_PULSE   =  10'd96;
    parameter logic [9:0] H_BACK    =  10'd48;
    parameter logic [9:0] V_ACTIVE  =  10'd480;
    parameter logic [9:0] V_FRONT   =  10'd10;
    parameter logic [9:0] V_PULSE   =  10'd2;
    parameter logic [9:0] V_BACK    =  10'd33;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;


    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end
        else begin
            case (h_state)
                H_ACTIVE_STATE: begin
                    h_counter   <= h_counter + 1;
                    if (h_counter == H_ACTIVE-1) begin
                        h_state <= H_FRONT_STATE;
                    end
                    hsync <= HIGH;
                end
                H_FRONT_STATE: begin
                    h_counter <= h_counter + H_FRONT-1;
                    if (h_counter == H_FRONT-1) begin
                        h_state <= H_PULSE_STATE;
                    end
                    hsync <= HIGH;
                end
                H_PULSE_STATE: begin
                    hsync <= LOW;
                    h_counter <= h_counter + H_PULSE-1;
                    if (h_counter == H_PULSE-1) begin
                        h_state <= H_BACK_STATE;
                    end
                end
                H_BACK_STATE: begin
                    h_counter <= h_counter + H_BACK-1;
                    if (h_counter == H_BACK-1) begin
                        h_state <= H_ACTIVE_STATE;
                        line_done <= HIGH;
                    end
                    hsync <= HIGH;
                end
            endcase

            case (v_state)
                V_ACTIVE_STATE: begin
                    v_counter <= v_counter + 1;
                    if (v_counter == V_ACTIVE-1) begin
                        v_state <= V_FRONT_STATE;
                    end
                    vsync <= HIGH;
                end
                V_FRONT_STATE: begin
                    v_counter <= v_counter + V_FRONT-1;
                    if (v_counter == V_FRONT-1) begin
                        v_state <= V_PULSE_STATE;
                    end
                    vsync <= HIGH;
                end
                V_PULSE_STATE: begin
                    vsync <= LOW;
                    v_counter <= v_counter + V_PULSE-1;
                    if (v_counter == V_PULSE-1) begin
                        v_state <= V_BACK_STATE;
                    end
                end
                V_BACK_STATE: begin
                    v_counter <= v_counter + V_BACK-1;
                    if (v_counter == V_BACK-1) begin
                        v_state <= V_ACTIVE_STATE;
                    end
                    vsync <= HIGH;
                end
            endcase

            default: begin
                red <= LOW;
                green <= LOW;
                blue <= LOW;
            endcase
        end
    end


    assign clk = clock;
    assign sync = 1'b0;
    assign blank = hsync & vsync;

    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

