module virtual2physical_tlb #(parameter ADDR_WIDTH = 8, PAGE_WIDTH = 8, TLB_SIZE = 4, PAGE_TABLE_SIZE = 16) (
    input clk,
    input reset,
    input [ADDR_WIDTH-1:0] virtual_address,
    output reg [PAGE_WIDTH-1:0] physical_address,
    output reg hit,
    output reg miss
);
    wire tlb_write_enable, flush, ready;
    wire [PAGE_WIDTH-1:0] page_table_entry;

    TLB #(.TLB_SIZE(TLB_SIZE), .ADDR_WIDTH(ADDR_WIDTH), .PAGE_WIDTH(PAGE_WIDTH)) tlb (
        .clk(clk),
        .reset(reset),
        .virtual_address(virtual_address),
        .tlb_write_enable(tlb_write_enable),
        .flush(flush),
        .page_table_entry(page_table_entry),
        .physical_address(physical_address),
        .hit(hit),
        .miss(miss)
    );

    PageTableHandler #(.ADDR_WIDTH(ADDR_WIDTH), .PAGE_WIDTH(PAGE_WIDTH), .PAGE_TABLE_SIZE(PAGE_TABLE_SIZE)) page_table_handler(
        .clk(clk),
        .reset(reset),
        .miss(miss),
        .virtual_page(virtual_address),
        .page_table_entry(page_table_entry),
        .ready(ready)
    );

    ControlUnit control_unit (
        .clk(clk),
        .reset(reset),
        .hit(hit),
        .miss(miss),
        .ready(ready),
        .tlb_write_enable(tlb_write_enable),
        .flush(flush)
    );

    // TLB Storage
    reg [ADDR_WIDTH-1:0] virtual_tags[TLB_SIZE-1:0];
    reg [PAGE_WIDTH-1:0] physical_pages[TLB_SIZE-1:0];
    reg [TLB_SIZE-1:0] valid_bits;
    reg [$clog2(TLB_SIZE)-1:0] replacement_index; // Index for the next replacement

    // Insert the logic here to update TLB with a new page table entry using the replacement policy

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            // Initialize TLB during reset
            valid_bits <= 0;
            replacement_index <= 0;
        end else begin
            hit = 0;
            miss = 1;
            physical_address = 0;

            // Insert the logic here to check for a match in TLB
            if (valid_bits[valid_bits]) begin
                hit <= 1;
                physical_address <= physical_pages[valid_bits];
            end else begin
                miss <= 1;
            end
        end
    end
endmodule

output.rtl/wishbone_to_ahb_bridge.sv:
module wishbone_to_ahb_bridge(
    input clk_i,
    input rst_i,
    input cyc_i,
    input stb_i,
    input [3:0] sel_i,
    input we_i,
    input [31:0] addr_i,
    input [31:0] data_i,
    output reg ack_o,
    output reg [31:0] data_o,
    output reg [1:0] hresp,
    output reg hready,
    output [1:0] htrans,
    output [2:0] hsize,
    output [2:0] hburst,
    output hwrite,
    output [31:0] haddr,
    output [31:0] hdata
);

    // Internal signals
    logic [31:0] a_data, a_addr;
    logic [31:0] b_data, b_addr;
    logic [2:0] h_size;
    logic h_burst = 3'b000;
    logic h_write;
    logic [1:0] h_trans;
    logic h_ready;

    // State Machine
    typedef enum logic [2:0] {IDLE, NON_SEQUENTIAL, BUSY} state_t;
    state_t state, next_state;

    // Endian Conversion
    function logic [31:0] convert_endian(input logic [31:0] data);
        return {data[31], data[30], data[29], data[28], data[27], data[26], data[25], data[24], data[23], data[22], data[21], data[20], data[19], data[18], data[17], data[16], data[15], data[14], data[13], data[12], data[11], data[10], data[9], data[8], data[7], data[6], data[5], data[4], data[3], data[2], data[1], data[0]};
    endfunction

    // Reset Behavior
    always @ (posedge clk_i or posedge rst_i) begin
        if (rst_i) begin
            state <= IDLE;
            ack_o <= 1'b0;
            hready <= 1'b0;
            hdata <= 32'b0;
            haddr <= 32'b0;
            hdata <= convert_endian(data_i);
        end else begin
            state <= next_state;
        end
    end

    // Transaction Phases
    always @ (*) begin
        case (state)
            IDLE: begin
                if (stb_i && cyc_i) begin
                    next_state = NON_SEQUENTIAL;
                end
            end
            NON_SEQUENTIAL: begin
                if (we_i) begin
                    a_data = convert_endian(data_i);
                    a_addr = {addr_i[31:24], sel_i};
                    hdata = a_data;
                    haddr = a_addr;
                    hwrite = 1'b1;
                    hsize = 3'b100; // Assuming byte-level transactions for simplicity
                    h_trans = 2'b01;
                    h_burst = h_burst;
                    h_size = hsize;
                    hready <= 1'b0;
                end
            end
            BUSY: begin
                if (hready) begin
                    hdata <= convert_endian(b_data);
                    haddr <= {b_addr[31:24], sel_i};
                    hwrite = 1'b0;
                    h_trans = 2'b01;
                    h_burst = h_burst;
                    h_size = hsize;
                    h_ready = 1'b1;
                end
            end
        endcase
    end

    // Outputs
    assign data_o = hdata;
    assign ack_o = 1'b1;
    assign hresp = hresp;

endmodule

output.rtl/Word_Change_Pulse.sv:
module Bit_Change_Detector (
    input  wire clk,          // Clock signal
    input  wire reset,       // Reset signal to initialize the module
    input  wire bit_in,      // Single bit input to detect changes
    output reg  change_pulse // Pulse signal indicating a change in the input bit
);

    reg bit_in_d;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            bit_in_d <= 1'b0;
            change_pulse <= 1'b0;
        end else begin
            bit_in_d <= bit_in;
        end
    end

    always @(*) begin
        if (bit_in_d != bit_in) begin
            change_pulse <= 1'b1;
            bit_in_d <= bit_in;
        end else begin
            change_pulse <= 1'b0;
        end
    end
endmodule

module Word_Change_Pulse#(
    parameter DATA_WIDTH = 8 // Default word width
) (
    input  wire                  clk,               // Clock signal for synchronizing operations
    input  wire                  reset,             // Reset signal to initialize the module
    input  wire [DATA_WIDTH-1:0] data_in,           // Input data, width defined by parameter DATA_WIDTH
    input  wire [DATA_WIDTH-1:0] mask,              // Mask signal to enable/disable change detection for each bit
    input  wire [DATA_WIDTH-1:0] match_pattern,     // Pattern to match for generating the pulse
    input  wire                  enable,            // Enable signal to allow module operation
    input  wire                  latch_pattern,     // Signal to latch the match pattern
    output reg                   word_change_pulse, // Output signal indicating a change in any bit of data_in
    output reg                   pattern_match_pulse, // Output signal indicating a match with the pattern
    output reg [DATA_WIDTH-1:0]  latched_pattern    // Latched pattern for comparison
);

    wire [DATA_WIDTH-1:0] change_pulses;
    wire [DATA_WIDTH-1:0] masked_data_in;
    wire [DATA_WIDTH-1:0] masked_change_pulses;
    wire match_detected;

    genvar i;

    // Instantiate Bit_Change_Detector modules for each bit
    generate
        for (i = 0; i < DATA_WIDTH; i++) begin
            Bit_Change_Detector bcd_bit(
                .clk(clk),
                .reset(reset),
                .bit_in(data_in[i] ^ mask[i]), // XOR operation to apply mask
                .change_pulse(masked_change_pulses[i])
            );
        end
    endgenerate

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            masked_data_in <= {DATA_WIDTH{1'b0}};
            masked_change_pulses <= {DATA_WIDTH{1'b0}};
            word_change_pulse <= 1'b0;
            pattern_match_pulse <= 1'b0;
            latched_pattern <= {DATA_WIDTH{1'b0}};
        end else if (enable) begin
            // Latch pattern if latch_pattern is asserted
            if (latch_pattern) begin
                latched_pattern <= match_pattern;
            end
            // Mask data_in, detect changes, and generate word_change_pulse
            masked_data_in <= (data_in ^ mask) & latched_pattern;
            change_pulses <= masked_data_in ^ masked_change_pulses;
            word_change_pulse <= change_pulses;
            // Compare masked data_in with latched_pattern & mask for pattern_match_pulse
            match_detected <= (masked_data_in & latched_pattern) && (masked_change_pulses & latched_pattern);
            pattern_match_pulse <= match_detected;
        end else begin
            // Handle the case when 'enable' is low
            word_change_pulse <= 1'b0;
            pattern_match_pulse <= 1'b0;
            latched_pattern <= {DATA_WIDTH{1'b0}};
        end
    end

endmodule

output.rtl/Data_Reduction.sv:
module Data_Reduction
#(
    parameter [2:0] REDUCTION_OP = 3'b000, // Default operation: AND
    parameter DATA_WIDTH         = 4,      // Width of each data element
    parameter DATA_COUNT         = 4,      // Number of data elements
    localparam TOTAL_INPUT_WIDTH = DATA_WIDTH * DATA_COUNT
)
(
    input  wire [TOTAL_INPUT_WIDTH-1:0] data_in,
    output reg  [DATA_WIDTH-1:0]        reduced_data_out
);

    generate
        genvar bit_index;

        // Iterate over each bit position within a single data word
        for (bit_index = 0; bit_index < DATA_WIDTH; bit_index = bit_index + 1) begin : bit_processing
            wire [DATA_COUNT-1:0] extracted_bits;

            // Extract corresponding bits from all data elements
            for (int i = 0; i < DATA_COUNT; i = i + 1) begin
                extracted_bits[i] = data_in[bit_index + i * DATA_WIDTH];
            end

            // Use Bitwise_Reduction module to perform the reduction operation
            wire [DATA_COUNT-1:0] reduced_bits;
            Bitwise_Reduction bitwise_reducer(
                .REDUCTION_OP(REDUCTION_OP),
                .BIT_COUNT(DATA_COUNT)
            );
            reduced_bits = bitwise_reducer.reduced_bit;

            // Combine the outputs of all Bitwise_Reduction modules to form the final reduced output data element
            case (bit_index)
                0: reduced_data_out = {reduced_bits[0], reduced_data_out[1:0]};
                1: reduced_data_out = {reduced_data_out[0], reduced_bits[1], reduced_data_out[2:0]};
                2: reduced_data_out = {reduced_data_out[0:1], reduced_bits[2], reduced_data_out[3]};
                3: reduced_data_out = {reduced_data_out[0:2], reduced_bits[3]};
                default: reduced_data_out = {reduced_data_out[0:3]};
            endcase

        end
    endgenerate

endmodule


module Bitwise_Reduction
#(
    parameter [2:0] REDUCTION_OP = 3'b000, // Default operation: AND
    parameter BIT_COUNT          = 4       // Number of bits to reduce
)
(
    input  wire [BIT_COUNT-1:0] input_bits,
    output reg                  reduced_bit
);

    // Reduction Operation Codes
    localparam [2:0] AND_OP  = 3'b000;
    localparam [2:0] OR_OP   = 3'b001;
    localparam [2:0] XOR_OP  = 3'b010;
    localparam [2:0] NAND_OP = 3'b011;
    localparam [2:0] NOR_OP  = 3'b100;
    localparam [2:0] XNOR_OP = 3'b101;

    int i;
    reg temp_result; // Intermediate result

    always @(*) begin
        // Initialize result with the first bit
        temp_result = input_bits[0];

        // Reduce bits using the selected operation
        for (i = 1; i < BIT_COUNT; i = i + 1) begin
            case (REDUCTION_OP)
                AND_OP, NAND_OP  : temp_result = temp_result & input_bits[i];
                OR_OP,  NOR_OP   : temp_result = temp_result | input_bits[i];
                XOR_OP, XNOR_OP  : temp_result = temp_result ^ input_bits[i];
                default          : temp_result = temp_result & input_bits[i];
            endcase
        end

        // Assign the reduced bit to the output
        reduced_bit = temp_result;
    end
endmodule

